INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('lengua', 'bachillerato', '{1}', '["Las jarchas mozárabes del siglo XI son los primeros textos líricos en lengua romance peninsular","Los cantares de gesta como el Cantar de Mio Cid difundieron la épica castellana en el siglo XII","El mester de clerecía cultivó la cuaderna vía con autores como Gonzalo de Berceo en el XIII","Don Juan Manuel perfeccionó la prosa narrativa didáctica con El conde Lucanor en el siglo XIV","El Arcipreste de Hita compuso el Libro de Buen Amor mezclando lo culto y lo popular"]'),
('lengua', 'bachillerato', '{1}', '["Jorge Manrique escribió las Coplas a la muerte de su padre como cumbre de la poesía elegíaca medieval","Las coplas reflexionan sobre la fugacidad de la vida usando tópicos como el ubi sunt","La estructura de las coplas avanza de lo universal a lo particular hasta llegar al padre","El estilo sencillo y solemne de Manrique marcó un modelo para la elegía en español","Las Coplas son una de las obras más antologadas y estudiadas de la literatura medieval castellana"]'),
('lengua', 'bachillerato', '{1}', '["La novela de caballerías alcanzó gran popularidad en el siglo XVI con Amadís de Gaula","La novela pastoril idealizaba la naturaleza y el amor siguiendo el modelo de la Diana de Montemayor","La novela morisca ofrecía una visión noble del mundo islámico en la España del XVI","La novela bizantina narraba viajes y aventuras con separaciones y reencuentros de amantes","Cervantes parodió la novela de caballerías y sintetizó todos estos géneros en el Quijote"]'),
('lengua', 'bachillerato', '{1}', '["El Lazarillo de Tormes inauguró la novela picaresca con un protagonista de clase baja en 1554","El pícaro narra su vida en primera persona desde la experiencia del desengaño social","Guzmán de Alfarache de Mateo Alemán continuó el género añadiendo reflexión moral en 1599","El Buscón de Quevedo llevó la picaresca al extremo del conceptismo y la crueldad satírica","La picaresca española influyó en la narrativa europea y anticipó rasgos de la novela realista moderna"]'),
('lengua', 'bachillerato', '{1}', '["Góngora desarrolló el culteranismo buscando la belleza formal con hipérbatos y metáforas complejas","Las Soledades de Góngora generaron una enorme polémica entre sus defensores y detractores","Quevedo representó el conceptismo con juegos de ingenio dobles sentidos y densidad de pensamiento","Lope de Vega cultivó una poesía más natural y accesible de gran variedad temática","La rivalidad literaria entre Góngora y Quevedo definió los dos polos de la estética barroca"]'),
('lengua', 'bachillerato', '{1}', '["La comedia nueva de Lope de Vega mezclaba personajes nobles y plebeyos en una misma obra","El gracioso se convirtió en un personaje tipo esencial del teatro barroco español","Los corrales de comedias eran los espacios públicos donde se representaban las obras teatrales","El público popular condicionaba las tramas exigiendo acción intriga y desenlaces satisfactorios","El teatro barroco español fue el espectáculo de masas más importante de los siglos XVI y XVII"]'),
('lengua', 'bachillerato', '{1}', '["El Cantar de Mio Cid se compuso hacia 1200 como la principal epopeya castellana conservada","El poema narra el destierro del Cid su lucha por recuperar la honra y el favor del rey","El Cid conquista Valencia y casa a sus hijas con los infantes de Carrión","Tras la afrenta de Corpes el Cid obtiene justicia en las cortes de Toledo","El cantar presenta al Cid como modelo de mesura lealtad y valor guerrero"]'),
('lengua', 'bachillerato', '{1}', '["El análisis morfológico descompone las palabras en sus unidades mínimas con significado llamadas morfemas","El lexema o raíz aporta el significado léxico de la palabra","Los morfemas flexivos indican género número persona tiempo y modo sin crear palabras nuevas","Los morfemas derivativos como prefijos y sufijos forman nuevas palabras por derivación","La composición une dos o más lexemas para formar una palabra compuesta como sacapuntas"]'),
('lengua', 'bachillerato', '{1}', '["Las categorías gramaticales clasifican las palabras según su función y su comportamiento sintáctico","El sustantivo nombra seres objetos o conceptos y funciona como núcleo del sintagma nominal","El adjetivo complementa al sustantivo aportando cualidades o determinación","El verbo expresa acciones estados o procesos y es el núcleo del sintagma verbal","Las preposiciones y conjunciones son palabras invariables que enlazan elementos dentro de la oración"]'),
('lengua', 'bachillerato', '{1}', '["Las oraciones compuestas coordinadas unen proposiciones independientes mediante conjunciones coordinantes","La coordinación copulativa suma significados con nexos como y e ni","La coordinación adversativa opone significados con nexos como pero sino o sin embargo","La coordinación disyuntiva presenta alternativas con nexos como o u o bien","La coordinación explicativa aclara lo dicho con nexos como es decir o sea o esto es"]'),
('lengua', 'bachillerato', '{1}', '["Las oraciones subordinadas sustantivas desempeñan funciones propias del sustantivo dentro de la principal","Las subordinadas adjetivas o de relativo complementan a un antecedente nominal como un adjetivo","Las subordinadas adverbiales funcionan como complementos circunstanciales de la oración principal","Las adverbiales propias expresan tiempo lugar y modo con nexos como cuando donde y como","Las adverbiales impropias expresan causa consecuencia condición concesión y finalidad"]'),
('lengua', 'bachillerato', '{1}', '["El texto argumentativo tiene como finalidad defender una tesis con razones y evidencias","La estructura típica incluye tesis cuerpo argumentativo con pruebas y conclusión","Los argumentos de autoridad citan a expertos para respaldar la posición del autor","Los contraargumentos anticipan objeciones del receptor para refutarlas y reforzar la tesis","La persuasión argumentativa combina razones lógicas con recursos retóricos y emocionales"]'),
('lengua', 'bachillerato', '{1}', '["Las propiedades textuales garantizan que un texto funcione como unidad comunicativa coherente","La adecuación ajusta el texto al contexto comunicativo al registro y al receptor","La coherencia organiza las ideas de forma lógica con un tema central y progresión temática","La cohesión conecta las oraciones mediante referencia sustitución elipsis y conectores","La corrección asegura el cumplimiento de las normas ortográficas gramaticales y léxicas"]'),
('lengua', 'bachillerato', '{1}', '["Fernando de Rojas publicó La Celestina en 1499 como tragicomedia en forma dialogada","Calisto y Melibea recurren a la alcahueta Celestina para facilitar sus encuentros amorosos","Celestina muere asesinada por los criados que reclaman su parte del pago","Calisto muere al caer de una tapia cuando acudía a ver a Melibea de noche","Melibea se suicida arrojándose desde una torre tras la muerte de su amante"]'),
('lengua', 'bachillerato', '{1}', '["El Marqués de Santillana cultivó la lírica culta del siglo XV con sus serranillas y sonetos","Juan de Mena escribió el Laberinto de Fortuna como poema alegórico culto y ambicioso","La poesía cancioneril del XV trató el amor cortés con virtuosismo formal y conceptual","La prosa del XV se enriqueció con crónicas libros de viajes y novelas sentimentales","El siglo XV fue un periodo de transición entre la literatura medieval y el Renacimiento"]'),
('lengua', 'bachillerato', '{1}', '["Garcilaso de la Vega adaptó el soneto petrarquista al castellano con maestría inigualable","Sus églogas presentan pastores que lamentan sus penas de amor en una naturaleza idealizada","La Égloga I alterna las voces de Salicio y Nemoroso sobre el amor perdido y la muerte","Garcilaso murió joven en combate en 1536 dejando una obra breve pero decisiva","Su poesía estableció el modelo lírico renacentista español que perduró durante décadas"]'),
('lengua', 'bachillerato', '{1}', '["Fray Luis de León buscó la armonía entre fe razón y belleza en su poesía","La Oda a la vida retirada exalta el ideal horaciano del beatus ille lejos del mundo","San Juan de la Cruz expresó la experiencia mística como unión amorosa del alma con Dios","El Cántico espiritual de San Juan sigue la estructura del Cantar de los Cantares bíblico","Santa Teresa de Jesús combinó la prosa autobiográfica con la descripción de sus experiencias místicas"]'),
('lengua', 'bachillerato', '{1}', '["La novela pastoril española se inició con La Diana de Jorge de Montemayor en 1559","Los pastores de la novela pastoril eran en realidad cortesanos disfrazados que debatían sobre el amor","La novela morisca como El Abencerraje idealizaba al moro como caballero noble y generoso","La novela bizantina narraba naufragios piratas y reencuentros como en Los trabajos de Persiles","Cervantes conocía y practicó todos estos subgéneros narrativos integrándolos en su obra"]'),
('lengua', 'bachillerato', '{1}', '["El Quijote de 1605 cuenta las aventuras de un hidalgo que enloquece leyendo libros de caballerías","Don Quijote confunde la realidad con la ficción caballeresca y sale a buscar aventuras","Sancho Panza acompaña a su señor como escudero práctico y materialista","En la segunda parte de 1615 los personajes conocen su propia fama literaria","El Quijote es considerado la primera novela moderna por su complejidad narrativa y su ironía"]'),
('lengua', 'bachillerato', '{1}', '["La prosa didáctica medieval se desarrolló en el siglo XIII con la Escuela de Traductores de Toledo","Alfonso X el Sabio impulsó la prosa castellana como lengua de cultura y ciencia","Don Juan Manuel elevó el cuento didáctico a categoría literaria con El conde Lucanor","Cada cuento sigue la estructura de un problema planteado a Patronio que responde con un ejemplo","La moraleja final se resume en un pareado que cierra la enseñanza del relato"]'),
('lengua', 'bachillerato', '{1}', '["El romancero viejo recogió poemas narrativos anónimos transmitidos oralmente desde el siglo XIV","Los romances históricos narraban episodios de la Reconquista y las luchas entre reinos","Los romances líricos y novelescos trataban temas amorosos y de aventura con tono emocional","En el siglo XVI los poetas cultos compusieron romances nuevos imitando el estilo tradicional","El romancero es una de las manifestaciones más originales y duraderas de la literatura española"]'),
('lengua', 'bachillerato', '{1}', '["El verbo es la categoría gramatical que expresa tiempo aspecto modo y persona","El aspecto verbal distingue entre acciones acabadas o perfectivas e inacabadas o imperfectivas","El modo indicativo presenta la acción como real el subjuntivo como posible o deseada","Las formas no personales son el infinitivo el gerundio y el participio","Las perífrasis verbales combinan un verbo auxiliar con una forma no personal para expresar matices"]'),
('lengua', 'bachillerato', '{1}', '["Los sintagmas son grupos de palabras organizados en torno a un núcleo que determina su función","El sintagma nominal tiene como núcleo un sustantivo o pronombre y puede incluir determinantes y complementos","El sintagma verbal tiene como núcleo el verbo y engloba todos los complementos del predicado","El sintagma adjetival tiene como núcleo un adjetivo que puede llevar complementos y modificadores","El sintagma preposicional se forma con una preposición seguida de un sintagma nominal como término"]'),
('lengua', 'bachillerato', '{1}', '["El complemento directo recibe la acción del verbo y puede sustituirse por los pronombres lo la los las","El complemento indirecto indica el destinatario de la acción y se sustituye por le o les","El complemento circunstancial expresa las circunstancias de tiempo lugar modo causa o instrumento","El complemento de régimen es exigido por el verbo y va introducido por una preposición fija","El complemento agente aparece en oraciones pasivas e indica quién realiza la acción verbal"]'),
('lengua', 'bachillerato', '{1}', '["La semántica estudia el significado de las palabras y sus relaciones dentro del sistema lingüístico","La sinonimia se da cuando dos palabras comparten significado aunque pueden diferir en matices","La antonimia establece oposición de significado entre palabras como grande y pequeño","La polisemia ocurre cuando una misma palabra tiene varios significados relacionados entre sí","La homonimia se produce cuando palabras de distinto origen coinciden en su forma pero no en su significado"]'),
('lengua', 'bachillerato', '{1}', '["Las variedades diatópicas son las diferencias lingüísticas determinadas por la geografía o dialecto","Las variedades diastráticas dependen del nivel sociocultural del hablante como culto o vulgar","Las variedades diafásicas se relacionan con la situación comunicativa y el registro formal o informal","El español tiene dialectos meridionales como el andaluz el canario y el español de América","La norma lingüística establece el uso correcto pero convive con la diversidad dialectal legítima"]'),
('lengua', 'bachillerato', '{1}', '["La oración simple consta de un solo predicado con su sujeto explícito o implícito","La oración compuesta contiene dos o más predicados relacionados entre sí","La yuxtaposición une oraciones sin nexo explícito separándolas por coma o punto y coma","La coordinación une oraciones del mismo nivel sintáctico mediante conjunciones coordinantes","La subordinación integra una oración dentro de otra como un constituyente de su estructura"]'),
('lengua', 'bachillerato', '{1}', '["El Libro de Buen Amor del Arcipreste de Hita mezcla lo religioso y lo profano con humor","La obra narra las aventuras amorosas del protagonista con un tono autobiográfico ficticio","Trotaconventos es una alcahueta que anticipa el personaje de Celestina un siglo después","El Arcipreste usa la cuaderna vía pero también metros juglarescos populares y líricos","La ambigüedad moral del libro ha generado interpretaciones múltiples durante siglos"]'),
('lengua', 'bachillerato', '{1}', '["El teatro medieval se originó en los tropos litúrgicos representados dentro de las iglesias","Las representaciones se trasladaron al exterior de los templos y luego a plazas públicas","Juan del Encina es considerado el padre del teatro español renacentista a finales del XV","Gil Vicente desarrolló el teatro en la corte portuguesa y española con farsas bilingües","Torres Naharro introdujo la división en jornadas y el concepto de decoro dramático"]'),
('lengua', 'bachillerato', '{1}', '["Los textos periodísticos informativos presentan hechos de actualidad de forma objetiva y verificable","La noticia responde a las seis preguntas básicas: qué quién cuándo dónde cómo y por qué","El reportaje amplía la información de la noticia con testimonios datos y contexto","Los textos periodísticos de opinión como el editorial y la columna expresan valoraciones subjetivas","La crónica combina información y valoración personal del periodista que ha presenciado los hechos"]'),
('lengua', 'bachillerato', '{1}', '["El cambio semántico modifica el significado de las palabras a lo largo del tiempo","La ampliación semántica extiende el significado original como ratón que pasó del animal al informático","La restricción semántica reduce el significado como lidiar que pasó de luchar a torear","La metáfora y la metonimia son mecanismos habituales del cambio semántico en las lenguas","Los préstamos lingüísticos incorporan palabras de otras lenguas adaptándolas al sistema propio"]'),
('lengua', 'bachillerato', '{1}', '["La formación de palabras en español se realiza por derivación composición y parasíntesis","La derivación añade prefijos o sufijos al lexema para crear nuevas palabras","La composición une dos o más lexemas independientes formando una palabra nueva","La parasíntesis combina simultáneamente prefijación y sufijación como en enrojecer","Los acrónimos y las siglas son mecanismos modernos de creación léxica muy productivos"]'),
('lengua', 'bachillerato', '{1}', '["La lírica tradicional castellana incluye villancicos cantigas de amigo y canciones populares","El villancico medieval era una composición breve con estribillo de tema amoroso o festivo","Las cantigas de amigo gallego-portuguesas expresaban la voz femenina que espera al amado","La lírica popular se transmitía oralmente y se recogió en cancioneros a partir del siglo XV","Los poetas cultos del Renacimiento reelaboraron temas y formas de la lírica popular tradicional"]'),
('lengua', 'bachillerato', '{1}', '["El soneto consta de catorce versos endecasílabos organizados en dos cuartetos y dos tercetos","Garcilaso introdujo el soneto en la poesía castellana siguiendo el modelo de Petrarca","El endecasílabo se convirtió en el verso culto por excelencia del Renacimiento y el Barroco","Los cuartetos suelen plantear el tema y los tercetos desarrollan la reflexión o el desenlace","El soneto ha pervivido como forma poética hasta la actualidad por su perfección estructural"]'),
('lengua', 'bachillerato', '{1}', '["El texto narrativo cuenta una secuencia de hechos protagonizados por personajes en un tiempo y espacio","El narrador puede ser omnisciente en tercera persona o protagonista en primera persona","La estructura narrativa clásica comprende planteamiento nudo y desenlace","Los personajes se caracterizan por sus acciones diálogos y descripciones físicas y psicológicas","El tiempo narrativo puede seguir el orden cronológico o alterarlo con analepsis y prolepsis"]'),
('lengua', 'bachillerato', '{1}', '["Calderón de la Barca dominó el teatro barroco español en la segunda mitad del siglo XVII","Sus dramas de honor como El alcalde de Zalamea planteaban conflictos entre honra y justicia","Los autos sacramentales de Calderón eran alegorías teológicas representadas en la fiesta del Corpus","El gran teatro del mundo presenta la vida como representación teatral ante la mirada de Dios","El estilo de Calderón es más intelectual y simbólico que el de Lope más popular y vital"]'),
('lengua', 'bachillerato', '{1}', '["La prosa barroca de Quevedo destaca por su sátira mordaz y su dominio del lenguaje conceptista","Los Sueños de Quevedo critican los vicios sociales mediante visiones alegóricas del infierno","Gracián formuló una teoría del ingenio y la agudeza como base de la estética conceptista","El Criticón de Gracián es una novela alegórica que narra el viaje de la vida humana","La prosa barroca oscila entre la sátira despiadada y la reflexión moral sobre la condición humana"]'),
('lengua', 'bachillerato', '{1}', '["La literatura medieval española refleja la convivencia de las tres culturas cristiana musulmana y judía","Las obras de debate como la Disputa del alma y el cuerpo enfrentaban posiciones opuestas","La prosa alfonsí del siglo XIII fijó el castellano como lengua de cultura y administración","El siglo XIV trajo crisis sociales que se reflejaron en una literatura más pesimista y satírica","El siglo XV supuso la transición al humanismo con autores como el Marqués de Santillana y Mena"]'),
('lengua', 'bachillerato', '{1}', '["Los conectores textuales organizan la información y guían al lector por el discurso","Los conectores aditivos suman ideas como además también e incluso","Los conectores de contraste oponen ideas como sin embargo no obstante y en cambio","Los conectores causales expresan la razón como porque ya que y puesto que","Los conectores consecutivos expresan la consecuencia como por tanto así pues y en consecuencia"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('lengua', 'bachillerato', '{2}', '["Camilo José Cela inauguró el tremendismo con La familia de Pascual Duarte en 1942","Carmen Laforet ganó el primer premio Nadal con Nada en 1945 retratando la posguerra barcelonesa","La colmena de Cela en 1951 ofreció un retrato coral de la sociedad madrileña de posguerra","El Jarama de Sánchez Ferlosio en 1956 llevó el objetivismo social a su máxima expresión","Delibes retrató el mundo rural castellano en obras como El camino y Las ratas"]'),
('lengua', 'bachillerato', '{2}', '["Tiempo de silencio de Martín Santos en 1962 rompió con el realismo social con técnicas experimentales","Juan Goytisolo experimentó con el lenguaje y la estructura en Señas de identidad en 1966","Juan Benet creó el territorio mítico de Región en Volverás a Región en 1967","La saga/fuga de J.B. de Torrente Ballester en 1972 mezcló realismo y fantasía con humor","La novela experimental española de los sesenta y setenta renovó las formas narrativas radicalmente"]'),
('lengua', 'bachillerato', '{2}', '["Eduardo Mendoza inauguró la nueva narrativa española con La verdad sobre el caso Savolta en 1975","La novela policíaca y negra se desarrolló con autores como Vázquez Montalbán y su detective Carvalho","Javier Marías exploró la memoria y la identidad en Corazón tan blanco en 1992","Antonio Muñoz Molina combinó intriga y reflexión histórica en El invierno en Lisboa y Plenilunio","La narrativa española actual se caracteriza por la pluralidad de tendencias y la recuperación del placer de contar"]'),
('lengua', 'bachillerato', '{2}', '["Los poetas de la Generación del 27 compartieron la admiración por Góngora y la poesía popular","García Lorca fusionó tradición y vanguardia en el Romancero gitano publicado en 1928","Alberti evolucionó desde el neopopularismo de Marinero en tierra hacia el surrealismo y el compromiso","Pedro Salinas exploró el amor como tema central en La voz a ti debida en 1933","Luis Cernuda construyó La realidad y el deseo como una autobiografía poética completa"]'),
('lengua', 'bachillerato', '{2}', '["Dámaso Alonso publicó Hijos de la ira en 1944 inaugurando la poesía desarraigada de posguerra","La poesía arraigada de Rosales y Panero buscó belleza y orden en medio de la desolación","La poesía social de los años cincuenta denunció la injusticia con autores como Blas de Otero y Celaya","Blas de Otero evolucionó del existencialismo religioso de Ángel fieramente humano al compromiso social","Gabriel Celaya proclamó la poesía como arma cargada de futuro al servicio del pueblo"]'),
('lengua', 'bachillerato', '{2}', '["La generación del 50 renovó la poesía social con un tono más intimista y reflexivo","Ángel González usó la ironía y el humor para expresar el desencanto y la crítica social","Jaime Gil de Biedma convirtió la experiencia personal en materia poética con tono conversacional","Claudio Rodríguez publicó Don de la ebriedad a los diecinueve años con un lirismo visionario","José Ángel Valente buscó la depuración extrema del lenguaje poético hacia el silencio y lo esencial"]'),
('lengua', 'bachillerato', '{2}', '["Los novísimos irrumpieron en 1970 con la antología de Castellet Nueve novísimos poetas españoles","Pere Gimferrer introdujo el culturalismo y las referencias cinematográficas en Arde el mar","Los novísimos rompieron con la poesía social reivindicando la autonomía del lenguaje poético","La poesía de la experiencia surgió en los ochenta con Luis García Montero como referente principal","La poesía española actual convive en múltiples tendencias desde el minimalismo hasta el neobarroco"]'),
('lengua', 'bachillerato', '{2}', '["Valle-Inclán creó el esperpento como deformación sistemática de la realidad española","Luces de bohemia de 1920 es la primera obra esperpéntica con Max Estrella recorriendo Madrid nocturno","El esperpento usa espejos cóncavos para distorsionar héroes clásicos y mostrar lo grotesco español","Los esperpentos de Martes de Carnaval satirizaron el militarismo y la política española","Valle-Inclán renovó el teatro español más que ningún otro autor de su generación"]'),
('lengua', 'bachillerato', '{2}', '["Tras la Guerra Civil el teatro español se dividió entre un teatro comercial y otro de renovación","Buero Vallejo estrenó Historia de una escalera en 1949 inaugurando el teatro realista de posguerra","Alfonso Sastre representó el teatro social comprometido con obras como Escuadra hacia la muerte","El teatro realista de los cincuenta y sesenta denunció las injusticias bajo la censura franquista","Buero Vallejo planteó en El tragaluz la cuestión de la memoria histórica y la culpa colectiva"]'),
('lengua', 'bachillerato', '{2}', '["Fernando Arrabal desarrolló el teatro pánico en el exilio combinando surrealismo y provocación","Francisco Nieva creó un teatro de farsa y fantasía alejado del realismo dominante","Los grupos de teatro independiente renovaron la escena española en los años setenta","Tras la Transición surgieron autores como José Luis Alonso de Santos con Bajarse al moro","El teatro español contemporáneo incluye autores como Juan Mayorga que reflexiona sobre la historia y la memoria"]'),
('lengua', 'bachillerato', '{2}', '["Federico García Lorca renovó el teatro con tragedias rurales de gran fuerza poética y dramática","Bodas de sangre de 1933 mezcla verso y prosa para narrar una pasión que conduce a la muerte","Yerma explora la frustración de una mujer estéril en una sociedad patriarcal opresiva","La casa de Bernarda Alba de 1936 enfrenta la autoridad tiránica con el deseo de libertad","El teatro de Lorca fusiona simbolismo popular y vanguardia con un lenguaje poético único"]'),
('lengua', 'bachillerato', '{2}', '["El comentario de texto EBAU requiere un resumen objetivo de no más de cinco o seis líneas","El tema del texto se formula en una frase breve que sintetiza la idea central del autor","La estructura del texto se analiza identificando tesis argumentos y conclusión si es argumentativo","El comentario crítico debe relacionar el contenido con el contexto social cultural o literario","La valoración personal debe ser argumentada evitando opiniones sin fundamento o resúmenes repetitivos"]'),
('lengua', 'bachillerato', '{2}', '["La cohesión léxica se logra mediante repeticiones sinónimos hiperónimos y campos semánticos","La cohesión gramatical emplea pronombres determinantes y elipsis para evitar redundancias","Los marcadores discursivos organizan el texto señalando orden adición contraste o conclusión","La deixis sitúa el enunciado en relación con el emisor el receptor el tiempo y el lugar","La modalización revela la actitud del emisor mediante adjetivos valorativos adverbios y verbos modales"]'),
('lengua', 'bachillerato', '{2}', '["Rafael Alberti publicó Marinero en tierra en 1925 con una lírica neopopularista luminosa","El poeta evolucionó hacia el surrealismo en Sobre los ángeles expresando una crisis espiritual profunda","Tras la Guerra Civil Alberti se exilió y su poesía se impregnó de nostalgia por España","En el exilio argentino e italiano mantuvo una producción constante de poesía comprometida y lírica","Regresó a España en 1977 y fue elegido diputado simbolizando la reconciliación cultural"]'),
('lengua', 'bachillerato', '{2}', '["Vicente Aleixandre recibió el Nobel de Literatura en 1977 como representante de la Generación del 27","Su primera etapa surrealista se plasma en La destrucción o el amor con imágenes cósmicas","Sombra del paraíso de 1944 evoca un mundo luminoso y primigenio anterior a la caída","En Historia del corazón de 1954 Aleixandre se acercó a una poesía más humana y solidaria","Su última etapa reflexiona sobre la vejez y el conocimiento en Diálogos del conocimiento"]'),
('lengua', 'bachillerato', '{2}', '["Miguel Hernández transitó de la poesía pura a la poesía comprometida y social","El rayo que no cesa de 1936 es un poemario de amor intenso en forma de sonetos","Durante la Guerra Civil escribió Viento del pueblo como poesía de trinchera y combate","Encarcelado tras la guerra compuso las Nanas de la cebolla dedicadas a su hijo","Hernández murió en prisión en 1942 siendo reconocido como puente entre el 27 y la posguerra"]'),
('lengua', 'bachillerato', '{2}', '["La novela de posguerra refleja una sociedad marcada por la represión la miseria y el aislamiento","La censura obligó a los novelistas a usar técnicas indirectas para criticar la realidad","El realismo social de los cincuenta pretendió ser testimonio objetivo de la injusticia social","La novela experimental de los sesenta incorporó monólogo interior fragmentación y múltiples perspectivas","La muerte de Franco en 1975 liberó la narrativa de las restricciones temáticas y formales"]'),
('lengua', 'bachillerato', '{2}', '["Las funciones del lenguaje según Jakobson se clasifican en seis tipos relacionados con la comunicación","La función referencial transmite información objetiva sobre la realidad extralingüística","La función emotiva expresa la actitud y los sentimientos del emisor ante el mensaje","La función conativa busca influir en el comportamiento del receptor mediante imperativos o vocativos","La función poética se centra en la forma del mensaje y es dominante en el lenguaje literario"]'),
('lengua', 'bachillerato', '{2}', '["Gonzalo Torrente Ballester combinó humor erudición y fantasía en su narrativa madura","Los gozos y las sombras es una trilogía que retrata la sociedad gallega de posguerra","La saga/fuga de J.B. mezcla mito historia y metaficción con un estilo lúdico y barroco","Miguel Delibes publicó Cinco horas con Mario en 1966 como monólogo interior de una viuda","Los santos inocentes de Delibes de 1981 denunció la explotación del campesinado extremeño"]'),
('lengua', 'bachillerato', '{2}', '["El ensayo español del siglo XX tiene antecedentes en los regeneracionistas y la Generación del 98","Ortega y Gasset reflexionó sobre España y Europa en La España invertebrada y La rebelión de las masas","María Zambrano desarrolló la razón poética como forma de conocimiento filosófico y literario","El ensayo de posguerra se refugió en temas culturales y estéticos ante la censura ideológica","El ensayo actual aborda temas diversos con autores como Fernando Savater y Adela Cortina"]'),
('lengua', 'bachillerato', '{2}', '["Las variedades del español en América se originaron con la colonización a partir de 1492","El español americano conserva rasgos del castellano del siglo XVI como el seseo generalizado","El voseo es un fenómeno gramatical propio de Argentina y otras zonas de Hispanoamérica","El léxico americano incorpora indigenismos del náhuatl quechua guaraní y otras lenguas originarias","El español es lengua oficial en veintiún países y tiene más de quinientos millones de hablantes"]'),
('lengua', 'bachillerato', '{2}', '["El Romanticismo español fue tardío y breve comparado con el de otros países europeos","Larra criticó las costumbres españolas en sus artículos periodísticos con ironía demoledora","Espronceda encarnó al poeta romántico rebelde con El estudiante de Salamanca y sus poesías","Bécquer publicó las Rimas póstumamente convirtiendo la poesía en expresión íntima del sentimiento","Rosalía de Castro inauguró la poesía gallega moderna con Cantares gallegos y Follas novas"]'),
('lengua', 'bachillerato', '{2}', '["El Naturalismo español adaptó las teorías de Zola sobre la herencia y el medio social","Emilia Pardo Bazán defendió el naturalismo en La cuestión palpitante generando gran polémica","Los pazos de Ulloa de Pardo Bazán retratan la decadencia de la nobleza rural gallega","Galdós incorporó técnicas naturalistas en novelas como Fortunata y Jacinta sin renunciar al humanismo","Clarín alcanzó la cumbre del naturalismo español con La Regenta una disección de la hipocresía provinciana"]'),
('lengua', 'bachillerato', '{2}', '["Las figuras retóricas son recursos expresivos que se desvían del uso habitual del lenguaje","La metáfora sustituye un término real por otro imaginario con el que guarda semejanza","La metonimia sustituye un término por otro con el que mantiene una relación de contigüidad","La anáfora repite una palabra al inicio de varios versos o frases para crear énfasis rítmico","El hipérbaton altera el orden sintáctico habitual para destacar un elemento o lograr efectos rítmicos"]'),
('lengua', 'bachillerato', '{2}', '["La Generación del 98 surgió tras el Desastre del 98 con la pérdida de las últimas colonias","Unamuno reflexionó sobre la identidad española y la angustia existencial en Del sentimiento trágico de la vida","Baroja creó una novelística de acción trepidante con personajes inconformistas y estilo directo","Azorín renovó la prosa descriptiva con frases breves y una mirada atenta al paisaje castellano","Machado evolucionó desde un modernismo intimista en Soledades hacia el compromiso ético en Campos de Castilla"]'),
('lengua', 'bachillerato', '{2}', '["El novecentismo o Generación del 14 buscó la modernización intelectual de España","Ortega y Gasset propuso la deshumanización del arte como tendencia de las nuevas vanguardias","Juan Ramón Jiménez persiguió la poesía pura desnuda de anécdota y ornamento","Ramón Gómez de la Serna inventó la greguería como fórmula literaria de humor y metáfora","Gabriel Miró cultivó una prosa lírica y sensorial que describe la luz y el paisaje mediterráneo"]'),
('lengua', 'bachillerato', '{2}', '["Los textos jurídicos y administrativos utilizan un lenguaje formal impersonal y formulario","Las características del lenguaje jurídico incluyen tecnicismos arcaísmos y sintaxis compleja","Los textos científicos emplean un vocabulario técnico preciso y una estructura expositiva rigurosa","El lenguaje publicitario combina recursos retóricos con estrategias persuasivas y emocionales","Cada tipo de texto tiene un registro lingüístico propio adaptado a su contexto comunicativo"]'),
('lengua', 'bachillerato', '{2}', '["La oración pasiva traslada el complemento directo a la posición de sujeto paciente","La pasiva refleja se construye con se y el verbo en tercera persona como se venden pisos","Las impersonales carecen de sujeto léxico y gramatical como llueve o hay problemas","Las construcciones con se pueden ser reflexivas recíprocas pasivas reflejas o impersonales","Distinguir los valores de se es una de las cuestiones sintácticas más frecuentes en la EBAU"]'),
('lengua', 'bachillerato', '{2}', '["La subordinada sustantiva funciona como sujeto complemento directo o término de preposición","Las sustantivas de sujeto aparecen con verbos como gustar interesar o ser necesario","Las sustantivas de complemento directo son las más frecuentes introducidas por que o si","La subordinada adjetiva especificativa restringe el significado del antecedente sin comas","La subordinada adjetiva explicativa añade información complementaria entre comas sin restringir"]'),
('lengua', 'bachillerato', '{2}', '["Las subordinadas adverbiales condicionales expresan una hipótesis con si como nexo principal","Las concesivas expresan un obstáculo que no impide la acción principal con aunque como nexo","Las consecutivas expresan la consecuencia de una intensidad con tanto que o tan que","Las causales explican el motivo de la acción principal con porque ya que o puesto que","Las finales expresan la intención o propósito de la acción principal con para que o a fin de que"]'),
('lengua', 'bachillerato', '{2}', '["Carmen Martín Gaite exploró la intimidad femenina y la memoria en novelas como El cuarto de atrás","Rosa Chacel desarrolló una narrativa intelectual influida por Ortega en Memorias de Leticia Valle","Ana María Matute recreó el mundo de la infancia y la Guerra Civil en Primera memoria","Almudena Grandes noveló la historia reciente de España en la serie Episodios de una guerra interminable","La narrativa femenina española ha ganado visibilidad y reconocimiento a lo largo del siglo XX y XXI"]'),
('lengua', 'bachillerato', '{2}', '["El español procede del latín vulgar hablado en la Hispania romana a partir del siglo III a.C.","Las invasiones germánicas del siglo V aportaron préstamos léxicos pero no alteraron la base latina","La presencia árabe durante ocho siglos dejó miles de arabismos en el vocabulario castellano","Las Glosas Emilianenses y Silenses del siglo X son los primeros testimonios escritos del romance","Alfonso X el Sabio consolidó el castellano como lengua de cultura y administración en el siglo XIII"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('filosofia', 'bachillerato', '{1}', '["Tales de Mileto propuso el agua como principio originario de todas las cosas en el siglo VI a.C.","Anaximandro amplió la idea y postuló el ápeiron como principio infinito e indeterminado","Anaxímenes eligió el aire como arjé explicando los cambios por condensación y rarefacción","Heráclito afirmó que todo fluye y que el fuego y el logos gobiernan el cambio universal","Parménides negó el cambio sosteniendo que el ser es único inmóvil y eterno"]'),
('filosofia', 'bachillerato', '{1}', '["Los sofistas enseñaban retórica y oratoria a cambio de dinero en la Atenas del siglo V a.C.","Protágoras declaró que el hombre es la medida de todas las cosas como tesis relativista","Gorgias cuestionó la posibilidad de conocer y comunicar la verdad con argumentos escépticos","Sócrates se opuso al relativismo sofista buscando definiciones universales mediante la dialéctica","El método socrático de preguntas y respuestas se conoce como mayéutica o arte de hacer parir ideas"]'),
('filosofia', 'bachillerato', '{1}', '["Platón distinguió entre el mundo sensible de las apariencias y el mundo inteligible de las Ideas","El Bien es la Idea suprema que ilumina todas las demás como el sol ilumina los objetos visibles","La alegoría de la caverna representa el ascenso del alma desde la ignorancia al conocimiento","La República propone que los filósofos deben gobernar porque conocen la verdad y la justicia","La teoría platónica influyó decisivamente en el pensamiento cristiano y en toda la filosofía occidental"]'),
('filosofia', 'bachillerato', '{1}', '["Aristóteles clasificó los saberes en teóricos prácticos y productivos según su finalidad","La física aristotélica explica el cambio mediante las cuatro causas: material formal eficiente y final","La metafísica estudia el ser en cuanto ser y los primeros principios de la realidad","La lógica aristotélica formuló el silogismo como forma básica de razonamiento deductivo","La política aristotélica concibe al ser humano como animal social que se realiza en la polis"]'),
('filosofia', 'bachillerato', '{1}', '["El estoicismo propuso vivir según la naturaleza aceptando con serenidad lo que no podemos cambiar","El epicureísmo buscó la felicidad en el placer moderado la amistad y la ausencia de dolor","El escepticismo académico suspendió el juicio sobre la posibilidad de alcanzar la verdad","El neoplatonismo de Plotino concibió la realidad como emanación del Uno principio supremo","Las escuelas helenísticas centraron la filosofía en la ética práctica y la búsqueda de la tranquilidad"]'),
('filosofia', 'bachillerato', '{1}', '["San Agustín conoció el maniqueísmo el escepticismo y el neoplatonismo antes de convertirse al cristianismo","Formuló la teoría de la iluminación divina como fuente del conocimiento de las verdades eternas","En La Ciudad de Dios distinguió entre la ciudad terrena del pecado y la celestial de la gracia","Su concepto de libre albedrío planteó el problema de la relación entre libertad humana y omnisciencia divina","San Agustín sentó las bases del pensamiento cristiano medieval durante casi un milenio"]'),
('filosofia', 'bachillerato', '{1}', '["Santo Tomás de Aquino estudió en París y Colonia con Alberto Magno aprendiendo la filosofía aristotélica","Formuló cinco vías para demostrar la existencia de Dios basadas en la causalidad y el movimiento","La Suma Teológica es su obra principal donde armoniza la fe cristiana con la razón aristotélica","Distinguió entre esencia y existencia en los seres creados que reciben su ser de Dios","La escolástica tomista se convirtió en la filosofía oficial de la Iglesia católica durante siglos"]'),
('filosofia', 'bachillerato', '{1}', '["El Renacimiento recuperó la confianza en la razón humana y en la capacidad de conocer la naturaleza","Maquiavelo separó la política de la moral religiosa en El Príncipe analizando el poder tal como es","La Reforma protestante de Lutero cuestionó la autoridad de la Iglesia y la tradición escolástica","Copérnico revolucionó la astronomía al proponer el modelo heliocéntrico del sistema solar","Galileo confirmó experimentalmente el heliocentrismo enfrentándose a la Inquisición por ello"]'),
('filosofia', 'bachillerato', '{1}', '["Descartes buscó un punto de partida indudable para el conocimiento mediante la duda metódica","El cogito ergo sum establece que la existencia del sujeto pensante es la primera certeza","Spinoza radicalizó el racionalismo concibiendo una única sustancia infinita que identificó con Dios o la Naturaleza","Leibniz propuso que la realidad se compone de mónadas unidades simples de fuerza y percepción","El racionalismo continental confió en la razón como fuente principal del conocimiento verdadero"]'),
('filosofia', 'bachillerato', '{1}', '["Locke negó las ideas innatas y afirmó que la mente al nacer es una tabula rasa","Berkeley llevó el empirismo al idealismo: solo existen las percepciones y la mente que las percibe","Hume distinguió entre impresiones vivaces y directas e ideas como copias débiles de las impresiones","La crítica de Hume a la causalidad la redujo a una costumbre psicológica sin fundamento racional","El empirismo británico limitó el conocimiento a lo que procede de la experiencia sensible"]'),
('filosofia', 'bachillerato', '{1}', '["El utilitarismo de Bentham propuso maximizar la felicidad del mayor número como principio moral","Mill perfeccionó el utilitarismo distinguiendo entre placeres superiores intelectuales e inferiores corporales","La ética kantiana del deber se opone al utilitarismo al juzgar la moralidad por la intención","El intuicionismo moral sostiene que captamos los valores de forma directa sin necesidad de razonamiento","El debate entre éticas teleológicas y deontológicas sigue vigente en la filosofía moral contemporánea"]'),
('filosofia', 'bachillerato', '{1}', '["El contractualismo de Hobbes justifica el Estado como pacto para salir del estado de guerra natural","Locke concibió el contrato social como garantía de los derechos naturales a la vida y la propiedad","Rousseau criticó la civilización como fuente de desigualdad y propuso la voluntad general como soberana","Montesquieu formuló la separación de poderes en legislativo ejecutivo y judicial como garantía de libertad","Las teorías contractualistas fundamentaron las revoluciones liberales del siglo XVIII y las democracias modernas"]'),
('filosofia', 'bachillerato', '{1}', '["La estética filosófica estudia la naturaleza de la belleza y la experiencia del arte","Platón desconfió del arte como imitación de imitaciones alejada de la verdad de las Ideas","Aristóteles valoró el arte como catarsis que purifica las emociones mediante la representación trágica","Kant distinguió entre lo bello que produce placer desinteresado y lo sublime que sobrecoge","Hegel concibió el arte como manifestación sensible de la Idea que evoluciona históricamente"]'),
('filosofia', 'bachillerato', '{1}', '["La filosofía de la ciencia estudia los métodos y fundamentos del conocimiento científico","El método inductivo de Bacon propone partir de observaciones particulares para formular leyes generales","El falsacionismo de Popper establece que una teoría es científica si puede ser refutada","Kuhn introdujo el concepto de paradigma y revolución científica como cambio de modelo teórico","Lakatos propuso los programas de investigación como unidades de análisis más amplias que las teorías aisladas"]'),
('filosofia', 'bachillerato', '{1}', '["La lógica proposicional estudia la relación entre proposiciones conectadas por operadores lógicos","La conjunción es verdadera solo cuando ambas proposiciones componentes son verdaderas","La disyunción inclusiva es verdadera cuando al menos una de las proposiciones es verdadera","El condicional es falso únicamente cuando el antecedente es verdadero y el consecuente falso","La tabla de verdad permite evaluar mecánicamente el valor de verdad de cualquier fórmula compuesta"]'),
('filosofia', 'bachillerato', '{1}', '["La antropología filosófica estudia qué es el ser humano como cuestión filosófica fundamental","Platón concibió al ser humano como alma racional encerrada en un cuerpo material","Aristóteles definió al ser humano como animal racional cuya alma es forma inseparable del cuerpo","Descartes lo entendió como res cogitans sustancia pensante distinta del cuerpo máquina","El existencialismo de Sartre afirma que la existencia precede a la esencia y el ser humano se hace a sí mismo"]'),
('filosofia', 'bachillerato', '{1}', '["La filosofía del lenguaje investiga la relación entre las palabras los pensamientos y la realidad","El primer Wittgenstein propuso la teoría pictórica: el lenguaje es una imagen lógica del mundo","El segundo Wittgenstein abandonó esa teoría y planteó los juegos de lenguaje como usos múltiples","Austin y Searle desarrollaron la teoría de los actos de habla como acciones realizadas al hablar","Habermas propuso la acción comunicativa como fundamento de la racionalidad y la democracia"]'),
('filosofia', 'bachillerato', '{1}', '["La justicia distributiva se ocupa del reparto equitativo de bienes y cargas en la sociedad","Rawls propuso el velo de la ignorancia como experimento mental para decidir principios justos","Nozick defendió un Estado mínimo que proteja derechos sin redistribuir la riqueza","El comunitarismo de MacIntyre y Taylor criticó el individualismo liberal reivindicando la comunidad","El debate entre liberalismo e igualitarismo sigue siendo central en la filosofía política actual"]'),
('filosofia', 'bachillerato', '{1}', '["Los derechos humanos se proclamaron universalmente en la Declaración de 1948 de las Naciones Unidas","Los derechos de primera generación son civiles y políticos como la libertad de expresión y el voto","Los derechos de segunda generación son sociales y económicos como la educación y la sanidad","Los derechos de tercera generación incluyen el medio ambiente la paz y el desarrollo sostenible","La fundamentación filosófica de los derechos humanos oscila entre el iusnaturalismo y el positivismo jurídico"]'),
('filosofia', 'bachillerato', '{1}', '["La falacia ad hominem ataca a la persona que argumenta en lugar de refutar sus razones","La falacia de autoridad apela a un experto que no tiene competencia en la materia discutida","La falacia de generalización precipitada extrae una conclusión universal a partir de pocos casos","La petición de principio presupone como premisa lo que se pretende demostrar en la conclusión","Identificar falacias es fundamental para desarrollar el pensamiento crítico y evaluar argumentos"]'),
('filosofia', 'bachillerato', '{1}', '["La ética de la virtud de Aristóteles propone cultivar hábitos buenos para alcanzar la vida plena","La prudencia o frónesis es la virtud intelectual que guía la acción moral en cada situación concreta","La justicia es la virtud que da a cada uno lo que le corresponde según Aristóteles","La valentía es el término medio entre la cobardía y la temeridad ante los peligros","La amistad es para Aristóteles una virtud esencial y lo más necesario para vivir bien"]'),
('filosofia', 'bachillerato', '{1}', '["La revolución científica del siglo XVII cambió la imagen del mundo con Galileo Kepler y Newton","Newton formuló la ley de gravitación universal unificando la física terrestre y celeste","El mecanicismo concibió la naturaleza como una gran máquina regida por leyes matemáticas","La Ilustración del XVIII aplicó la razón científica a la política la religión y la moral","Kant definió la Ilustración como la salida del hombre de su minoría de edad autoculpable"]'),
('filosofia', 'bachillerato', '{1}', '["La bioética reflexiona sobre los dilemas morales que plantean los avances de la medicina y la biología","La eutanasia plantea el conflicto entre el derecho a morir dignamente y el respeto a la vida","La manipulación genética abre posibilidades terapéuticas pero también riesgos de eugenesia","El principio de autonomía respeta la capacidad del paciente para tomar decisiones sobre su salud","La bioética busca un equilibrio entre el progreso científico y la dignidad de la persona"]'),
('filosofia', 'bachillerato', '{1}', '["La democracia ateniense fue el primer sistema donde los ciudadanos participaban directamente en el gobierno","La democracia representativa moderna surgió con las revoluciones liberales del siglo XVIII","La separación de poderes garantiza que ningún órgano del Estado concentre todo el poder","Los partidos políticos canalizan la participación ciudadana y compiten en elecciones libres","La democracia contemporánea enfrenta retos como la desafección ciudadana y la desinformación digital"]'),
('filosofia', 'bachillerato', '{1}', '["El existencialismo de Kierkegaard planteó la angustia como experiencia fundamental de la libertad humana","Heidegger analizó la existencia humana como ser-en-el-mundo arrojado a la temporalidad","Sartre proclamó que el ser humano está condenado a ser libre sin excusas ni determinismos","Simone de Beauvoir aplicó el existencialismo a la condición femenina en El segundo sexo","Camus exploró el absurdo de la existencia y la rebeldía como respuesta al sinsentido de la vida"]'),
('filosofia', 'bachillerato', '{1}', '["La epistemología estudia las condiciones los límites y la naturaleza del conocimiento humano","El realismo sostiene que existe una realidad independiente del sujeto que la conoce","El idealismo afirma que la realidad depende en algún grado de la mente que la percibe","El escepticismo duda de la posibilidad de alcanzar un conocimiento seguro y definitivo","El pragmatismo juzga la verdad de una idea por sus consecuencias prácticas y su utilidad"]'),
('filosofia', 'bachillerato', '{1}', '["La Ilustración francesa se desarrolló en torno a la Enciclopedia de Diderot y D Alembert","Voltaire defendió la tolerancia religiosa y la libertad de pensamiento con su sátira mordaz","Montesquieu analizó las formas de gobierno y propuso la separación de poderes como garantía","Rousseau denunció la desigualdad social y propuso la educación natural en el Emilio","Los ilustrados franceses prepararon intelectualmente el terreno para la Revolución de 1789"]'),
('filosofia', 'bachillerato', '{1}', '["La ética aplicada examina problemas morales concretos utilizando principios filosóficos generales","La ética medioambiental cuestiona si la naturaleza tiene valor intrínseco o solo instrumental","La ética animal debate si los animales tienen derechos basándose en su capacidad de sufrimiento","La ética de la inteligencia artificial plantea dilemas sobre responsabilidad y sesgo algorítmico","La reflexión ética es indispensable para afrontar los desafíos morales de las sociedades tecnológicas"]'),
('filosofia', 'bachillerato', '{1}', '["El empirismo lógico del Círculo de Viena propuso el criterio de verificación como base del significado","El principio de verificabilidad afirma que solo las proposiciones comprobables empíricamente tienen sentido","Popper rechazó la verificación y propuso la falsabilidad como criterio de demarcación científica","Kuhn mostró que la ciencia no avanza linealmente sino por rupturas entre paradigmas incompatibles","Feyerabend defendió el anarquismo epistemológico argumentando que no hay un método científico único"]'),
('filosofia', 'bachillerato', '{1}', '["La filosofía de la mente estudia la naturaleza de la conciencia y su relación con el cerebro","El dualismo cartesiano separó la mente como sustancia pensante del cuerpo como sustancia extensa","El materialismo identifica los estados mentales con estados cerebrales físicos y observables","El funcionalismo define los estados mentales por su función no por su composición material","El problema de la conciencia sigue siendo uno de los grandes misterios de la filosofía contemporánea"]'),
('filosofia', 'bachillerato', '{1}', '["Empédocles propuso cuatro elementos como raíces de todo: tierra agua aire y fuego","Anaxágoras postuló las homeomerías como partículas infinitas gobernadas por el Nous o inteligencia","Demócrito y Leucipo crearon el atomismo: la realidad se compone de átomos y vacío","Los atomistas explicaron todos los fenómenos naturales por el movimiento y choque de los átomos","El pluralismo presocrático intentó resolver la tensión entre ser y cambio de Parménides y Heráclito"]'),
('filosofia', 'bachillerato', '{1}', '["La retórica es el arte de persuadir mediante el discurso según la definición de Aristóteles","El ethos apela a la credibilidad del orador como persona de confianza y autoridad moral","El pathos busca conmover emocionalmente al auditorio para ganar su adhesión","El logos se basa en la argumentación racional con pruebas y razonamientos lógicos","El pensamiento crítico requiere distinguir entre los tres tipos de apelación para evaluar discursos"]'),
('filosofia', 'bachillerato', '{1}', '["El relativismo moral sostiene que los valores dependen de cada cultura y no hay moral universal","El universalismo moral defiende que existen principios éticos válidos para todas las culturas","El emotivismo de Hume y Ayer reduce los juicios morales a expresiones de aprobación o rechazo","El constructivismo moral propone que los valores se construyen mediante el diálogo racional","La tensión entre relativismo y universalismo es uno de los debates centrales de la ética contemporánea"]'),
('filosofia', 'bachillerato', '{1}', '["La utopía de Tomás Moro de 1516 imaginó una sociedad ideal sin propiedad privada","Bacon describió una sociedad gobernada por la ciencia en La Nueva Atlántida","Las utopías socialistas del XIX propusieron modelos de sociedad igualitaria y cooperativa","Las distopías del siglo XX como 1984 de Orwell alertaron sobre los peligros del totalitarismo","El pensamiento utópico mantiene viva la crítica social y la imaginación de alternativas posibles"]'),
('filosofia', 'bachillerato', '{1}', '["El problema del mal cuestiona cómo un Dios omnipotente y bueno puede permitir el sufrimiento","Leibniz acuñó el término teodicea para justificar a Dios argumentando que este es el mejor mundo posible","Voltaire ridiculizó el optimismo leibniziano en Cándido tras el terremoto de Lisboa de 1755","Kant rechazó toda teodicea teórica y situó el sentido moral como única respuesta al problema del mal","El problema del mal sigue siendo un argumento central en el debate filosófico sobre la existencia de Dios"]'),
('filosofia', 'bachillerato', '{1}', '["La lógica de predicados amplía la proposicional analizando la estructura interna de las proposiciones","El cuantificador universal afirma que una propiedad se cumple para todos los individuos del dominio","El cuantificador existencial afirma que al menos un individuo cumple la propiedad indicada","Las reglas de inferencia permiten deducir conclusiones válidas a partir de premisas dadas","La lógica formal es una herramienta fundamental para evaluar la corrección de los razonamientos"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('filosofia', 'bachillerato', '{2}', '["Platón nació en Atenas en 427 a.C. en el seno de una familia aristocrática influyente","La muerte de Sócrates en 399 a.C. marcó profundamente su vocación filosófica y política","Fundó la Academia de Atenas hacia 387 a.C. como centro de investigación filosófica y científica","Viajó tres veces a Siracusa intentando llevar a la práctica su ideal de gobierno filosófico","La Academia perduró durante nueve siglos siendo la institución educativa más longeva de la Antigüedad"]'),
('filosofia', 'bachillerato', '{2}', '["Platón dividió el alma en tres partes: racional irascible y concupiscible","La parte racional busca la verdad y debe gobernar a las otras dos partes del alma","La parte irascible aporta el coraje y la voluntad necesarios para seguir a la razón","La parte concupiscible alberga los deseos corporales y necesita ser controlada por la razón","La justicia del individuo consiste en que cada parte del alma cumpla su función armónicamente"]'),
('filosofia', 'bachillerato', '{2}', '["El mito del carro alado de Platón representa el alma como un auriga con dos caballos","El caballo blanco simboliza los impulsos nobles y obedece al auriga racional","El caballo negro representa los deseos desordenados que dificultan el ascenso del alma","El auriga lucha por elevar el alma hacia el mundo de las Ideas contemplando la verdad","La caída del alma al cuerpo se produce cuando los deseos vencen y el alma pierde las alas"]'),
('filosofia', 'bachillerato', '{2}', '["Aristóteles desarrolló la teoría hilemórfica: toda sustancia se compone de materia y forma","La materia es el sustrato pasivo y la forma es el principio activo que determina qué es algo","El acto es la realización plena de un ser y la potencia es su capacidad de cambiar","El movimiento se explica como el paso de la potencia al acto guiado por una causa final","El Primer Motor Inmóvil es acto puro sin materia que mueve todo sin ser movido"]'),
('filosofia', 'bachillerato', '{2}', '["Aristóteles clasificó las virtudes en éticas del carácter e intelectuales del pensamiento","La virtud ética es un hábito de elegir el término medio determinado por la razón prudente","La prudencia o frónesis es la virtud intelectual que delibera correctamente sobre lo bueno","La justicia es la virtud más importante porque regula las relaciones entre los ciudadanos","La felicidad suprema consiste en la actividad contemplativa la forma más elevada de vida racional"]'),
('filosofia', 'bachillerato', '{2}', '["Aristóteles formuló las reglas del silogismo como forma básica de razonamiento deductivo","Un silogismo consta de dos premisas y una conclusión con tres términos: mayor menor y medio","El término medio aparece en ambas premisas pero no en la conclusión conectando los extremos","La validez del silogismo depende de su forma lógica no del contenido de las premisas","La silogística fue el sistema lógico dominante en Occidente hasta la lógica matemática del siglo XIX"]'),
('filosofia', 'bachillerato', '{2}', '["Descartes escribió las Meditaciones metafísicas en 1641 desarrollando su sistema filosófico completo","La primera meditación aplica la duda metódica: los sentidos pueden engañar y un genio maligno podría manipularnos","La segunda meditación alcanza el cogito como primera verdad: si pienso necesariamente existo","La tercera meditación demuestra la existencia de Dios como causa de la idea de infinito en nuestra mente","Las meditaciones restantes fundamentan la ciencia en la veracidad de Dios que garantiza las ideas claras"]'),
('filosofia', 'bachillerato', '{2}', '["Descartes estableció las reglas del método: evidencia análisis síntesis y enumeración","La regla de evidencia exige no aceptar como verdadero nada que no sea claro y distinto","El análisis divide los problemas complejos en partes más simples para examinarlas","La síntesis reconstruye el conocimiento desde los elementos más simples a los más complejos","La enumeración revisa todo el proceso para asegurar que no se ha omitido ningún paso"]'),
('filosofia', 'bachillerato', '{2}', '["Hume dividió los contenidos mentales en impresiones directas y vivas e ideas como sus copias débiles","Toda idea legítima debe derivar de una impresión previa: si no hay impresión la idea carece de fundamento","Las relaciones de ideas como las matemáticas son verdades necesarias pero no informan sobre el mundo","Las cuestiones de hecho son contingentes y solo se conocen por la experiencia nunca con certeza absoluta","La distinción entre relaciones de ideas y cuestiones de hecho es la horquilla de Hume"]'),
('filosofia', 'bachillerato', '{2}', '["Hume analizó la causalidad como una de las relaciones fundamentales del pensamiento humano","Observamos contigüidad espacial sucesión temporal y conjunción constante entre dos fenómenos","La conexión necesaria entre causa y efecto no se observa ni se deduce: es un hábito mental","La costumbre o hábito nos lleva a esperar que el futuro se parezca al pasado sin garantía racional","La crítica humeana de la causalidad sacudió los fundamentos de la metafísica y la ciencia"]'),
('filosofia', 'bachillerato', '{2}', '["Hume extendió su empirismo a la moral: los juicios morales se basan en sentimientos no en la razón","El sentimiento de aprobación ante acciones útiles o agradables fundamenta nuestra moralidad","La razón sola no puede mover a la acción: solo las pasiones nos impulsan a actuar","La simpatía nos permite compartir los sentimientos ajenos y es la base de la vida moral","El emotivismo moral de Hume se opone al racionalismo ético de la tradición platónica y kantiana"]'),
('filosofia', 'bachillerato', '{2}', '["Kant publicó la Crítica de la razón pura en 1781 buscando los límites del conocimiento humano","Distinguió entre juicios analíticos que no aportan información y sintéticos que amplían el conocimiento","Los juicios sintéticos a priori son universales y necesarios pero aportan conocimiento nuevo","El espacio y el tiempo son formas puras de la sensibilidad que estructuran toda experiencia","Las categorías del entendimiento como sustancia y causalidad organizan los datos sensibles en conocimiento"]'),
('filosofia', 'bachillerato', '{2}', '["La revolución copernicana de Kant invierte la relación entre sujeto y objeto en el conocimiento","No es el sujeto quien se adapta al objeto sino el objeto el que se adapta a las condiciones del sujeto","El fenómeno es la realidad tal como aparece configurada por nuestras formas de conocer","El noúmeno o cosa en sí es la realidad tal como es independientemente del sujeto pero incognoscible","Esta distinción establece los límites del conocimiento teórico dejando fuera la metafísica como ciencia"]'),
('filosofia', 'bachillerato', '{2}', '["La ética kantiana es formal y deontológica: juzga la moralidad por el deber no por las consecuencias","El imperativo categórico ordena incondicionalmente: obra de modo que tu máxima pueda ser ley universal","La segunda formulación exige tratar a la humanidad siempre como fin y nunca solo como medio","La autonomía moral significa que el sujeto racional se da a sí mismo la ley moral","La buena voluntad que actúa por deber es lo único bueno sin restricción según Kant"]'),
('filosofia', 'bachillerato', '{2}', '["Marx parte de la dialéctica hegeliana pero sustituye la Idea por las condiciones materiales de producción","La infraestructura económica constituida por las fuerzas y relaciones de producción determina la superestructura","La superestructura incluye el derecho la política la religión y la ideología que justifican el orden vigente","La lucha de clases es el motor de la historia desde las sociedades esclavistas hasta el capitalismo","La ideología dominante presenta los intereses de la clase dominante como intereses universales naturales"]'),
('filosofia', 'bachillerato', '{2}', '["Marx analizó la mercancía como unidad básica del capitalismo con valor de uso y valor de cambio","El trabajo humano es la fuente de todo valor según la teoría del valor-trabajo","La plusvalía es la diferencia entre el valor producido por el trabajador y el salario que recibe","La acumulación de plusvalía genera la concentración de capital y la creciente desigualdad","Marx predijo que las contradicciones internas del capitalismo llevarían a su superación histórica"]'),
('filosofia', 'bachillerato', '{2}', '["Marx describió cuatro formas de alienación del trabajador en el sistema capitalista","El trabajador está alienado respecto al producto de su trabajo que no le pertenece","Está alienado respecto al proceso de producción donde realiza tareas repetitivas y sin sentido","Está alienado respecto a su ser genérico: pierde su capacidad creativa y su humanidad","Está alienado respecto a los demás: las relaciones humanas se convierten en relaciones mercantiles"]'),
('filosofia', 'bachillerato', '{2}', '["Nietzsche criticó la tradición filosófica occidental por negar la vida en favor de un mundo ideal","La moral judeocristiana es para Nietzsche una moral de esclavos nacida del resentimiento de los débiles","La moral de señores afirma los valores vitales como la fuerza la creatividad y la voluntad de poder","La muerte de Dios significa que los fundamentos tradicionales de la moral occidental se han derrumbado","El nihilismo es la consecuencia de la pérdida de los valores supremos que orientaban la cultura occidental"]'),
('filosofia', 'bachillerato', '{2}', '["Nietzsche propuso la transvaloración de todos los valores como superación del nihilismo europeo","El superhombre es el ser humano capaz de crear nuevos valores desde la afirmación de la vida","La voluntad de poder no es dominio político sino impulso creativo de autoafirmación vital","El eterno retorno plantea la pregunta de si amaríamos la vida lo suficiente para desear revivirla infinitamente","La filosofía de Nietzsche influyó decisivamente en el existencialismo la posmodernidad y el arte del siglo XX"]'),
('filosofia', 'bachillerato', '{2}', '["Nietzsche distinguió entre lo apolíneo como orden y medida y lo dionisíaco como éxtasis y pasión","En El nacimiento de la tragedia vinculó la decadencia cultural con la represión de lo dionisíaco","El método genealógico investiga el origen histórico y psicológico de los conceptos morales","La genealogía de la moral revela que los valores morales no son eternos sino productos históricos","Nietzsche usó el aforismo y el estilo literario como formas filosóficas contra el sistema académico"]'),
('filosofia', 'bachillerato', '{2}', '["Ortega y Gasset nació en Madrid en 1883 y estudió filosofía en Alemania con los neokantianos","Formuló el raciovitalismo como superación del racionalismo abstracto y del irracionalismo vitalista","La vida es para Ortega la realidad radical: yo soy yo y mi circunstancia","El perspectivismo sostiene que cada individuo capta la realidad desde su perspectiva irrenunciable","La verdad total se compone de la suma de todas las perspectivas individuales complementarias"]'),
('filosofia', 'bachillerato', '{2}', '["Ortega analizó la sociedad de masas en La rebelión de las masas publicada en 1929","El hombre-masa vive sin exigirse nada y se conforma con ser igual a todos los demás","La minoría selecta no se define por privilegio sino por autoexigencia y vocación de excelencia","Ortega criticó que las masas ocupen funciones rectoras sin la preparación ni el esfuerzo necesarios","La obra anticipó problemas de las democracias modernas como el populismo y la mediocridad cultural"]'),
('filosofia', 'bachillerato', '{2}', '["Ortega desarrolló una teoría de las generaciones como motor del cambio histórico","Cada generación comparte una sensibilidad vital determinada por su circunstancia histórica","Las generaciones cumulativas aceptan el mundo heredado y las polémicas lo cuestionan radicalmente","La razón histórica comprende la vida humana como un relato que se desarrolla en el tiempo","España invertebrada de 1921 diagnosticó los males de España como falta de minoría selecta y proyecto común"]'),
('filosofia', 'bachillerato', '{2}', '["La Escuela de Frankfurt fundada en 1923 desarrolló la teoría crítica de la sociedad","Horkheimer y Adorno denunciaron la razón instrumental que domina la naturaleza y al ser humano","La industria cultural transforma el arte en mercancía y a los ciudadanos en consumidores pasivos","Marcuse describió al hombre unidimensional alienado por la sociedad de consumo capitalista","Habermas propuso la acción comunicativa y la ética del discurso como alternativa a la razón instrumental"]'),
('filosofia', 'bachillerato', '{2}', '["La hermenéutica filosófica estudia la interpretación de textos y la comprensión del sentido","Gadamer desarrolló la hermenéutica como fusión de horizontes entre el intérprete y lo interpretado","El círculo hermenéutico describe la relación entre la comprensión de las partes y la del todo","Los prejuicios no son solo negativos: forman parte de nuestra precomprensión histórica del mundo","La hermenéutica influyó en las ciencias humanas subrayando que toda comprensión es histórica e interpretativa"]'),
('filosofia', 'bachillerato', '{2}', '["Hannah Arendt analizó el totalitarismo como fenómeno político sin precedentes en el siglo XX","En Los orígenes del totalitarismo estudió el antisemitismo el imperialismo y el terror estatal","Acuñó el concepto de banalidad del mal al observar el juicio de Eichmann en Jerusalén","La condición humana distingue tres actividades fundamentales: labor trabajo y acción política","Arendt reivindicó la esfera pública como espacio de libertad y participación ciudadana"]'),
('filosofia', 'bachillerato', '{2}', '["El posmodernismo cuestionó los grandes relatos del progreso la razón y la emancipación universal","Lyotard declaró el fin de los grandes relatos y la legitimación del saber por performatividad","Foucault analizó cómo el poder se ejerce a través del saber y las instituciones disciplinarias","Derrida desarrolló la deconstrucción como estrategia para revelar las oposiciones ocultas en los textos","El pensamiento posmoderno ha generado un debate continuo sobre los límites de la razón y la verdad"]'),
('filosofia', 'bachillerato', '{2}', '["La filosofía de la tecnología reflexiona sobre el impacto de la técnica en la vida humana","Heidegger advirtió que la técnica moderna reduce la naturaleza a un fondo explotable","Jonas formuló el principio de responsabilidad ante las consecuencias futuras de la acción tecnológica","La ética de la inteligencia artificial plantea problemas de autonomía sesgo y responsabilidad","La reflexión filosófica es imprescindible para orientar éticamente el desarrollo tecnológico actual"]'),
('filosofia', 'bachillerato', '{2}', '["La fenomenología de Husserl propuso volver a las cosas mismas describiendo los fenómenos tal como aparecen","La reducción fenomenológica suspende la actitud natural para examinar las estructuras de la conciencia","La intencionalidad indica que toda conciencia es siempre conciencia de algo dirigida a un objeto","Heidegger transformó la fenomenología en analítica existencial del Dasein o ser-ahí","La fenomenología influyó decisivamente en el existencialismo la hermenéutica y la psiquiatría del siglo XX"]'),
('filosofia', 'bachillerato', '{2}', '["Hume rechazó la idea de un yo sustancial permanente reduciéndolo a un haz de percepciones","El yo no es una impresión sino una ficción construida por la imaginación y la memoria","La identidad personal es una ilusión creada por la continuidad y semejanza de nuestras percepciones","Kant respondió a Hume proponiendo el yo trascendental como condición formal de toda experiencia","El debate sobre la identidad personal sigue vivo en la filosofía de la mente contemporánea"]'),
('filosofia', 'bachillerato', '{2}', '["Kant distinguió tres tipos de ideas de la razón pura: alma mundo y Dios","Las antinomias de la razón muestran que podemos demostrar tesis contradictorias sobre el mundo","La imposibilidad de resolver las antinomias prueba que la metafísica no puede ser ciencia teórica","Los postulados de la razón práctica recuperan Dios libertad e inmortalidad como exigencias morales","Kant estableció así los límites del conocimiento teórico para dar espacio a la fe racional y la moral"]'),
('filosofia', 'bachillerato', '{2}', '["Platón describió cuatro grados de conocimiento: eikasía pístis diánoia y nóesis","La eikasía es el nivel más bajo: la captación de imágenes y sombras del mundo sensible","La pístis es la creencia basada en la percepción directa de los objetos físicos","La diánoia es el conocimiento discursivo propio de las matemáticas que usa hipótesis","La nóesis es la intuición intelectual directa de las Ideas alcanzada por la dialéctica filosófica"]'),
('filosofia', 'bachillerato', '{2}', '["Marx y Engels publicaron el Manifiesto Comunista en 1848 declarando la lucha de clases como motor histórico","Marx distinguió cinco modos de producción: comunismo primitivo esclavismo feudalismo capitalismo y comunismo","Cada modo de producción contiene contradicciones internas que generan su transformación histórica","El Estado es para Marx un instrumento de dominación de la clase propietaria sobre la trabajadora","La dictadura del proletariado sería una fase transitoria hacia la sociedad sin clases ni Estado"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('latin', 'bachillerato', '{1}', '["Roma pasó de ser una aldea de pastores en el Lacio a una potencia peninsular en tres siglos","La República romana se estableció en el 509 a.C. tras la expulsión del último rey etrusco","Las Guerras Púnicas contra Cartago convirtieron a Roma en la potencia dominante del Mediterráneo","La expansión militar trajo riqueza y esclavos pero también tensiones sociales internas","Los hermanos Graco intentaron reformas agrarias que fueron frenadas por la oligarquía senatorial"]'),
('latin', 'bachillerato', '{1}', '["La familia romana estaba gobernada por el pater familias que tenía autoridad absoluta","La matrona romana dirigía el hogar supervisaba a los esclavos y educaba a los hijos pequeños","Los niños romanos asistían a la escuela del grammaticus donde aprendían lectura escritura y cálculo","A los dieciséis años los varones recibían la toga virilis marcando su entrada en la vida adulta","Las mujeres romanas no tenían derechos políticos pero gozaban de cierta libertad social y económica"]'),
('latin', 'bachillerato', '{1}', '["El nominativo es el caso del sujeto y del atributo en las oraciones latinas","El acusativo indica el complemento directo y se usa con ciertas preposiciones de dirección","El genitivo expresa posesión pertenencia o la materia de la que algo está hecho","El dativo señala el complemento indirecto o el beneficiario de la acción verbal","El ablativo expresa circunstancias como instrumento compañía lugar procedencia y causa"]'),
('latin', 'bachillerato', '{1}', '["La primera declinación latina tiene el tema en -a y agrupa mayoritariamente sustantivos femeninos","La segunda declinación tiene temas en -o/-us y agrupa sustantivos masculinos y neutros","La tercera declinación es la más variada con temas en consonante y en vocal -i","La cuarta declinación tiene tema en -u y la quinta en -e ambas con pocos sustantivos","Conocer la declinación de un sustantivo es imprescindible para traducir correctamente el latín"]'),
('latin', 'bachillerato', '{1}', '["Los adjetivos latinos de la primera clase se declinan por la primera y segunda declinación","Los adjetivos de la segunda clase se declinan por la tercera declinación con tema en -i","Los grados del adjetivo son positivo comparativo con sufijo -ior y superlativo con -issimus","Bonus tiene comparativo melior y superlativo optimus como formas irregulares","La concordancia del adjetivo con el sustantivo en género número y caso es obligatoria en latín"]'),
('latin', 'bachillerato', '{1}', '["El presente de indicativo activo se forma con el tema de presente más las desinencias personales","El pretérito imperfecto añade el infijo -ba- al tema de presente en las cuatro conjugaciones","El futuro imperfecto usa -bi- en la primera y segunda conjugación y -a-/-e- en la tercera y cuarta","El pretérito perfecto se forma sobre el tema de perfecto más desinencias propias como -i -isti -it","El pluscuamperfecto y el futuro perfecto se construyen sobre el tema de perfecto con sufijos específicos"]'),
('latin', 'bachillerato', '{1}', '["La oración de infinitivo latina equivale a una subordinada sustantiva en español","El sujeto de la oración de infinitivo se pone en acusativo no en nominativo","El infinitivo puede ser de presente perfecto o futuro según el tiempo de la acción","Verbos como dico puto credo y scio rigen habitualmente oraciones de infinitivo","La traducción de las oraciones de infinitivo requiere identificar el acusativo sujeto correctamente"]'),
('latin', 'bachillerato', '{1}', '["Las oraciones subordinadas latinas de relativo se introducen por el pronombre qui quae quod","El pronombre relativo concuerda con su antecedente en género y número pero no en caso","El caso del relativo depende de la función que desempeña dentro de su propia oración","Las subordinadas causales se introducen por quod quia y quoniam con indicativo o subjuntivo","Las subordinadas temporales usan conjunciones como cum ubi postquam y antequam"]'),
('latin', 'bachillerato', '{1}', '["Eneas huyó de Troya en llamas llevando a su padre Anquises sobre los hombros","Tras años de navegación llegó a Cartago donde la reina Dido se enamoró de él","Los dioses le ordenaron partir hacia Italia y Dido se suicidó desesperada por su abandono","Eneas descendió al mundo de los muertos donde su padre le mostró el futuro glorioso de Roma","Finalmente llegó al Lacio venció a Turno y fundó la estirpe que daría origen a Roma"]'),
('latin', 'bachillerato', '{1}', '["Las termas eran centros de baño públicos donde los romanos socializaban y se ejercitaban","El anfiteatro era el escenario de los combates de gladiadores y las venationes con animales","El circo albergaba las carreras de cuadrigas que apasionaban a toda la sociedad romana","El teatro romano adaptó las comedias y tragedias griegas al gusto del público latino","Los espectáculos públicos eran financiados por políticos y emperadores para ganar el favor del pueblo"]'),
('latin', 'bachillerato', '{1}', '["Plauto fue el primer gran comediógrafo latino que adaptó la comedia nueva griega al público romano","Sus obras como Aulularia y Miles gloriosus presentan personajes tipo como el soldado fanfarrón y el avaro","Terencio refinó la comedia latina con tramas más elaboradas y un lenguaje más elegante","Las comedias de Terencio como El eunuco exploraban conflictos familiares y sociales con humanismo","La comedia latina influyó decisivamente en el teatro europeo posterior desde Shakespeare hasta Molière"]'),
('latin', 'bachillerato', '{1}', '["Los pronombres personales latinos son ego tú nos y vos para las dos primeras personas","La tercera persona carece de pronombre personal propio y usa demostrativos como is ea id","Los pronombres demostrativos hic iste e ille señalan proximidad intermedia y lejanía respectivamente","El pronombre relativo qui quae quod introduce oraciones subordinadas adjetivas","Los pronombres indefinidos como aliquis y quidam expresan indeterminación del referente"]'),
('latin', 'bachillerato', '{1}', '["Augusto estableció el Principado en el 27 a.C. inaugurando la época imperial romana","Su reinado trajo la Pax Romana un periodo de estabilidad y prosperidad en todo el imperio","Augusto promovió las artes y la literatura con el mecenazgo de Virgilio Horacio y Ovidio","Construyó monumentos como el Ara Pacis que celebraban la paz y la grandeza de Roma","La edad de Augusto es considerada la época dorada de la literatura y la cultura latinas"]'),
('latin', 'bachillerato', '{1}', '["Las calzadas romanas conectaban todas las provincias del imperio facilitando el comercio y la comunicación","Los acueductos transportaban agua desde manantiales lejanos hasta las ciudades con ingeniería precisa","El Coliseo de Roma podía albergar a cincuenta mil espectadores en sus gradas escalonadas","El Panteón de Roma tiene una cúpula de hormigón con un óculo central abierto al cielo","La ingeniería romana alcanzó logros que no se superaron en Europa durante más de un milenio"]'),
('latin', 'bachillerato', '{1}', '["Catulo fue un poeta neotérico que introdujo la lírica personal y amorosa en la literatura latina","Sus poemas a Lesbia expresan las distintas fases del amor desde la pasión hasta el desengaño","Horacio cultivó la oda y la sátira con un estilo equilibrado y un ideal de vida serena","Las Odas de Horacio celebran la amistad el vino y el carpe diem como arte de vivir","Ovidio narró las transformaciones míticas en las Metamorfosis una obra que influyó en toda la cultura europea"]'),
('latin', 'bachillerato', '{1}', '["La religión romana era politeísta y asimilaba divinidades de los pueblos conquistados","Los romanos practicaban la adivinación consultando el vuelo de las aves y las entrañas de animales","El culto al emperador se convirtió en un instrumento de cohesión política en el Imperio","El cristianismo se difundió por el Imperio romano a pesar de las persecuciones iniciales","El Edicto de Milán del 313 legalizó el cristianismo y Teodosio lo declaró religión oficial en el 380"]'),
('latin', 'bachillerato', '{1}', '["Los numerales cardinales latinos son unus duo tres quattuor quinque sex septem octo novem decem","Los numerales ordinales indican orden: primus secundus tertius quartus quintus","Los distributivos expresan reparto: singuli bini terni quaterni quini","Los multiplicativos expresan multiplicación: simplex duplex triplex quadruplex","El sistema numérico romano usaba letras como I V X L C D M para representar cantidades"]'),
('latin', 'bachillerato', '{1}', '["El subjuntivo latino expresa deseo posibilidad duda o irrealidad a diferencia del indicativo","El subjuntivo presente se forma cambiando la vocal temática: a por e en la primera conjugación","El subjuntivo imperfecto se reconoce por el infijo -re- añadido al tema de presente","El subjuntivo perfecto y pluscuamperfecto se forman sobre el tema de perfecto con sufijos propios","El uso del subjuntivo en subordinadas depende de la conjunción y de la relación temporal con la principal"]'),
('latin', 'bachillerato', '{1}', '["El participio de presente se declina como un adjetivo de la tercera declinación","El participio de perfecto se forma sobre el supino y funciona como adjetivo de la primera y segunda","El participio de futuro expresa la intención de realizar una acción inminente","La construcción de ablativo absoluto usa un participio en ablativo con un sustantivo concordante","El ablativo absoluto equivale a una oración subordinada circunstancial de tiempo causa o condición"]'),
('latin', 'bachillerato', '{1}', '["Lucrecio escribió De rerum natura exponiendo la filosofía epicúrea en verso hexámetro","Séneca cultivó la filosofía estoica en sus epístolas y tratados morales escritos en prosa","Las Cartas a Lucilio de Séneca reflexionan sobre la muerte el tiempo y la virtud","Marco Aurelio emperador y filósofo escribió sus Meditaciones como diario estoico personal","La filosofía grecolatina se difundió en Roma adaptándose al carácter práctico de la mentalidad romana"]'),
('latin', 'bachillerato', '{1}', '["El derecho romano se codificó en las Doce Tablas hacia el 450 a.C. como primera ley escrita","Los juristas romanos desarrollaron conceptos como persona propiedad contrato y delito","El Corpus Iuris Civilis de Justiniano en el siglo VI recopiló todo el derecho romano clásico","Los principios del derecho romano como la presunción de inocencia perviven en los sistemas jurídicos actuales","El latín jurídico ha dejado expresiones vigentes como habeas corpus in dubio pro reo y de facto"]'),
('latin', 'bachillerato', '{1}', '["La voz pasiva latina se forma con desinencias propias en los tiempos del tema de presente","En los tiempos de perfecto la pasiva se construye con el participio perfecto y el verbo esse","El agente de la pasiva se expresa con la preposición a o ab seguida de ablativo","La transformación de activa a pasiva convierte el CD en sujeto y el sujeto en ablativo agente","Dominar la voz pasiva es esencial para traducir correctamente textos historiográficos y jurídicos latinos"]'),
('latin', 'bachillerato', '{1}', '["Los prefijos latinos como in- ex- re- pre- y sub- siguen vivos en las lenguas romances actuales","Los sufijos latinos como -tion -ment y -ble formaron la base de la derivación en español y francés","El vocabulario científico internacional se construye mayoritariamente con raíces griegas y latinas","La etimología permite comprender el significado originario de las palabras y sus relaciones semánticas","Conocer el latín facilita el aprendizaje simultáneo de varias lenguas romances como español francés e italiano"]'),
('latin', 'bachillerato', '{1}', '["Julio César fue asesinado en los idus de marzo del 44 a.C. por conspiradores republicanos","Marco Antonio pronunció un discurso funerario que encendió al pueblo contra los asesinos","Octavio sobrino y heredero de César formó el segundo triunvirato con Antonio y Lépido","La batalla de Accio en el 31 a.C. enfrentó a Octavio contra Antonio y Cleopatra","Octavio venció y recibió el título de Augusto inaugurando el periodo imperial en el 27 a.C."]'),
('latin', 'bachillerato', '{1}', '["La educación romana comenzaba en el hogar donde la madre enseñaba las primeras letras","El litterator enseñaba a leer escribir y contar a los niños a partir de los siete años","El grammaticus instruía en literatura latina y griega analizando textos de poetas y oradores","El rhetor completaba la formación del joven romano enseñándole el arte de la oratoria pública","Los jóvenes de familias acomodadas completaban su educación viajando a Atenas o Rodas"]'),
('latin', 'bachillerato', '{1}', '["Los verbos deponentes tienen forma pasiva pero significado activo como loquor hablar y sequor seguir","Los verbos semideponentes son activos en los tiempos de presente y deponentes en los de perfecto","Los verbos irregulares como sum y sus compuestos possum y prosum tienen conjugación propia","El verbo eo y sus compuestos como abeo y redeo presentan irregularidades en el tema de presente","Fero y sus compuestos como affero y confero combinan temas supletivos de distinto origen"]'),
('latin', 'bachillerato', '{1}', '["El hexámetro dactílico es el verso épico por excelencia usado por Virgilio y Homero","Cada pie del hexámetro puede ser un dáctilo de una larga y dos breves o un espondeo de dos largas","La cantidad vocálica distingue sílabas largas de breves y determina el ritmo del verso latino","La cesura es una pausa dentro del verso que divide el hexámetro en dos hemistiquios","La métrica latina se basa en la alternancia de sílabas largas y breves a diferencia del español que cuenta sílabas"]'),
('latin', 'bachillerato', '{1}', '["Tito Livio escribió Ab Urbe Condita una historia monumental de Roma desde su fundación","Salustio narró la Conjuración de Catilina y la Guerra de Jugurta con estilo conciso y moralizante","César describió sus propias campañas militares en los Comentarios con aparente objetividad","Tácito denunció la tiranía imperial en los Anales y las Historias con un estilo incisivo","La historiografía latina combinaba el relato de hechos con la reflexión moral y política"]'),
('latin', 'bachillerato', '{1}', '["Los romanos dividían el día en doce horas de luz que variaban de duración según la estación","La cena era la comida principal del día y se celebraba al atardecer con varios platos","Los romanos vestían la toga como prenda formal y la túnica como vestido cotidiano","Las insulae eran bloques de viviendas populares de varios pisos donde vivía la plebe urbana","Las domus eran casas unifamiliares con atrio peristilo y triclinio donde habitaban las familias acomodadas"]'),
('latin', 'bachillerato', '{1}', '["Las conjunciones subordinantes latinas introducen distintos tipos de oraciones dependientes","Ut con subjuntivo puede introducir finales completivas o consecutivas según el contexto","Ne introduce oraciones finales negativas y completivas con verbos de temor","Cum con subjuntivo tiene valor causal concesivo o circunstancial según el tiempo verbal","Si introduce oraciones condicionales que pueden ser reales potenciales o irreales"]'),
('latin', 'bachillerato', '{1}', '["El supino latino tiene dos formas: el supino en -um de acusativo y el supino en -u de ablativo","El supino en acusativo expresa finalidad con verbos de movimiento como eo lusum voy a jugar","El gerundio latino es un sustantivo verbal que se declina por los casos oblicuos","El gerundivo es un adjetivo verbal de obligación como Carthago delenda est Cartago debe ser destruida","La perifrástica pasiva con gerundivo más esse expresa obligación o necesidad de forma impersonal"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('latin', 'bachillerato', '{2}', '["Virgilio compuso las Bucólicas como diez poemas pastoriles inspirados en Teócrito","Las Geórgicas celebran la vida agrícola como metáfora de la virtud y el esfuerzo humano","La Eneida fue encargada por Augusto como epopeya nacional del pueblo romano","Eneas es presentado como modelo de pietas: piedad hacia los dioses la patria y la familia","La Eneida se convirtió en la obra cumbre de la literatura latina y referente de toda la épica occidental"]'),
('latin', 'bachillerato', '{2}', '["Cicerón dominó la oratoria latina con discursos que combinaban elocuencia y argumentación jurídica","Las Catilinarias son cuatro discursos que desenmascaran la conspiración de Catilina contra la República","Las Filípicas atacan a Marco Antonio como amenaza para la libertad republicana","El De Oratore expone la formación ideal del orador que debe dominar todas las artes liberales","La prosa ciceroniana se convirtió en el modelo del latín clásico durante siglos"]'),
('latin', 'bachillerato', '{2}', '["Las Metamorfosis de Ovidio reúnen más de doscientos cincuenta mitos de transformación","La obra comienza con el caos primordial y termina con la apoteosis de Julio César","Ovidio fue desterrado por Augusto a Tomis junto al Mar Negro en el año 8 d.C.","Desde el exilio escribió Tristia y Epistulae ex Ponto lamentando su alejamiento de Roma","Las Metamorfosis fueron la fuente principal de mitología para el arte europeo durante siglos"]'),
('latin', 'bachillerato', '{2}', '["Horacio formuló el carpe diem en sus Odas como invitación a disfrutar el presente","Las Sátiras de Horacio critican los vicios humanos con humor e ironía sin acritud","Las Epístolas reflexionan sobre la vida buena la poesía y la filosofía con tono conversacional","El Ars Poetica estableció preceptos sobre la creación literaria que influyeron durante siglos","Horacio propuso el ideal de aurea mediocritas como vida equilibrada lejos de los extremos"]'),
('latin', 'bachillerato', '{2}', '["Séneca el filósofo fue tutor y consejero del emperador Nerón durante sus primeros años de gobierno","Sus Diálogos filosóficos como De la brevedad de la vida reflexionan sobre el buen uso del tiempo","Las Epístolas morales a Lucilio exponen la doctrina estoica en forma de cartas amistosas","Las tragedias de Séneca como Medea y Fedra influyeron decisivamente en el teatro renacentista","Nerón ordenó el suicidio de Séneca en el año 65 d.C. que el filósofo afrontó con serenidad estoica"]'),
('latin', 'bachillerato', '{2}', '["La sintaxis de los casos es la clave para comprender y traducir correctamente el latín","El doble acusativo aparece con verbos como doceo que rige acusativo de persona y de cosa","El genitivo partitivo indica el todo del que se toma una parte como pars civium","El dativo de finalidad expresa el propósito como auxilio venire venir en ayuda","El ablativo de cualidad describe una característica con un sustantivo y adjetivo concordantes"]'),
('latin', 'bachillerato', '{2}', '["Las oraciones condicionales latinas se clasifican en reales potenciales e irreales","Las reales usan indicativo en prótasis y apódosis expresando condiciones cumplibles","Las potenciales usan subjuntivo presente o perfecto para condiciones posibles pero inciertas","Las irreales de presente usan subjuntivo imperfecto expresando condiciones contrarias a la realidad actual","Las irreales de pasado usan subjuntivo pluscuamperfecto para condiciones imposibles ya en el pasado"]'),
('latin', 'bachillerato', '{2}', '["Tácito es considerado el mayor historiador latino por su análisis psicológico y político","Los Anales narran la historia de Roma desde Tiberio hasta Nerón con estilo incisivo y sentencioso","Las Historias cubren el periodo desde Galba hasta Domiciano con un tono sombrío y crítico","La Germania describe las costumbres de los pueblos germánicos como espejo moral de Roma","El Agrícola es una biografía laudatoria de su suegro gobernador de Britania"]'),
('latin', 'bachillerato', '{2}', '["La consecutio temporum regula la concordancia temporal entre la oración principal y la subordinada","Si la principal está en tiempo primario la subordinada usa subjuntivo presente o perfecto","Si la principal está en tiempo histórico la subordinada usa subjuntivo imperfecto o pluscuamperfecto","La anterioridad se expresa con perfecto o pluscuamperfecto de subjuntivo según el tiempo de la principal","Dominar la consecutio es imprescindible para traducir correctamente textos con subordinación compleja"]'),
('latin', 'bachillerato', '{2}', '["La literatura latina arcaica comenzó con Livio Andrónico que tradujo la Odisea al latín","Nevio compuso la primera epopeya histórica latina sobre la primera guerra púnica","Ennio escribió los Annales en hexámetros narrando la historia de Roma desde sus orígenes","La comedia latina alcanzó su esplendor con Plauto y Terencio en los siglos III y II a.C.","La literatura arcaica sentó las bases formales y temáticas de toda la producción literaria latina posterior"]'),
('latin', 'bachillerato', '{2}', '["El estilo indirecto latino convierte todas las oraciones del discurso original en subordinadas","Las afirmaciones se transforman en oraciones de infinitivo con sujeto en acusativo","Las preguntas se convierten en interrogativas indirectas con subjuntivo","Las órdenes se expresan mediante subjuntivo en lugar del imperativo directo","La transformación al estilo indirecto exige aplicar las reglas de la consecutio temporum"]'),
('latin', 'bachillerato', '{2}', '["La epigrafía latina estudia las inscripciones grabadas en piedra metal y otros materiales duraderos","Las inscripciones funerarias revelan nombres oficios edades y sentimientos de los romanos comunes","Las inscripciones honoríficas registran las carreras políticas y militares de los magistrados","Los grafitis de Pompeya muestran la lengua coloquial y la vida cotidiana de los ciudadanos","La epigrafía es una fuente fundamental para conocer la historia social y lingüística del mundo romano"]'),
('latin', 'bachillerato', '{2}', '["El latín medieval fue la lengua de la Iglesia la universidad y la diplomacia durante siglos","La Vulgata de San Jerónimo tradujo la Biblia al latín en el siglo IV como texto de referencia","El latín carolingio del siglo IX recuperó la corrección gramatical con la reforma educativa de Carlomagno","Las universidades medievales como Bolonia París y Salamanca usaron el latín como lengua docente","El humanismo renacentista del XV recuperó el latín clásico de Cicerón como modelo de elegancia"]'),
('latin', 'bachillerato', '{2}', '["Apuleyo escribió El asno de oro la única novela latina conservada completa","La obra narra la metamorfosis de Lucio en asno y sus aventuras hasta ser rescatado por Isis","Petronio compuso el Satiricón una novela picaresca ambientada en la Roma de Nerón","La cena de Trimalción es el episodio más famoso del Satiricón por su sátira del nuevo rico","La narrativa latina en prosa anticipó temas y técnicas que reaparecerían en la novela europea moderna"]'),
('latin', 'bachillerato', '{2}', '["Marcial cultivó el epigrama como composición breve e ingeniosa con un final sorprendente","Sus más de mil quinientos epigramas retratan la vida cotidiana de la Roma imperial con humor ácido","Juvenal escribió dieciséis sátiras que denuncian con indignación los vicios de la sociedad romana","La sátira tercera de Juvenal describe las incomodidades y peligros de vivir en la gran Roma","La poesía satírica y epigramática latina influyó en autores como Quevedo y los escritores ilustrados"]'),
('latin', 'bachillerato', '{2}', '["Plinio el Viejo compiló la Historia Natural una enciclopedia del saber antiguo en treinta y siete libros","La obra abarca astronomía geografía zoología botánica mineralogía y artes plásticas","Plinio el Joven describió en sus Cartas la erupción del Vesubio que mató a su tío en el 79 d.C.","Las cartas de Plinio el Joven a Trajano documentan la administración provincial y el trato a los cristianos","La curiosidad enciclopédica de los Plinios refleja el afán romano por catalogar y comprender el mundo"]'),
('latin', 'bachillerato', '{2}', '["El cursus honorum era la carrera política que todo romano ambicioso debía seguir paso a paso","El primer cargo era la cuestura que se ocupaba de las finanzas públicas a partir de los treinta años","La edilidad se encargaba del mantenimiento de la ciudad los mercados y los espectáculos públicos","La pretura otorgaba funciones judiciales y el mando de un ejército en provincias","El consulado era la magistratura suprema con dos cónsules elegidos anualmente como jefes del Estado"]'),
('latin', 'bachillerato', '{2}', '["La caída del Imperio Romano de Occidente se produjo oficialmente en el 476 d.C.","Las invasiones germánicas presionaron las fronteras del imperio durante todo el siglo V","La división del imperio en Occidente y Oriente por Teodosio en 395 debilitó la parte occidental","Rómulo Augústulo fue depuesto por Odoacro jefe de los hérulos como último emperador de Occidente","El Imperio de Oriente con capital en Constantinopla sobrevivió mil años más hasta 1453"]'),
('latin', 'bachillerato', '{2}', '["Las figuras retóricas latinas incluyen la anáfora la antítesis el hipérbaton y la litote","La anáfora repite una palabra al inicio de varias frases para crear énfasis y ritmo","La antítesis contrapone ideas opuestas en estructuras paralelas para resaltar el contraste","El hipérbaton altera el orden natural de las palabras para destacar un elemento del enunciado","La litote niega lo contrario de lo que se quiere afirmar como non ignoro en vez de scio"]'),
('latin', 'bachillerato', '{2}', '["El calendario romano original tenía diez meses y fue reformado por Numa Pompilio a doce","Julio César reformó el calendario en el 46 a.C. estableciendo el año de trescientos sesenta y cinco días","El mes de julio se nombró en honor a Julio César y agosto en honor a Augusto","Las calendas eran el primer día del mes los idus el día trece o quince y las nonas el quinto o séptimo","El calendario juliano se usó en Europa durante más de mil seiscientos años hasta la reforma gregoriana de 1582"]'),
('latin', 'bachillerato', '{2}', '["El latín ha legado al español miles de cultismos que conservan la forma latina original","Los cultismos como nocturno ígneo y acuático mantienen la fonética latina sin evolución popular","Las palabras patrimoniales como noche fuego y agua evolucionaron fonéticamente desde el latín vulgar","Los dobletes son parejas de palabras con el mismo origen latino pero distinta evolución como íntegro y entero","El estudio de la evolución fonética del latín al español es fundamental para comprender el léxico castellano"]'),
('latin', 'bachillerato', '{2}', '["Fedro adaptó las fábulas de Esopo al verso latino en el siglo I d.C. con moraleja explícita","La fábula del lobo y el cordero ilustra cómo el poderoso siempre encuentra pretextos para abusar","Las fábulas de Fedro critican la injusticia social con animales que representan tipos humanos","Higino recopiló mitos y leyendas en sus Fabulae como manual de referencia mitológica","La tradición fabulística latina pervivió en la Edad Media y llegó hasta La Fontaine en el siglo XVII"]'),
('latin', 'bachillerato', '{2}', '["San Agustín escribió las Confesiones como primera autobiografía espiritual de la literatura occidental","La obra narra su conversión al cristianismo desde el pecado y la búsqueda intelectual","San Isidoro de Sevilla compiló las Etimologías como enciclopedia del saber antiguo en el siglo VII","Boecio escribió La consolación de la filosofía en prisión antes de ser ejecutado por Teodorico","Estos autores transmitieron la cultura clásica latina a la Edad Media cristiana"]'),
('latin', 'bachillerato', '{2}', '["Las preposiciones latinas rigen acusativo o ablativo según su significado y contexto","Ad e in con acusativo expresan dirección hacia un lugar o finalidad","In y sub con ablativo expresan ubicación estática dentro de o debajo de","Algunas preposiciones como in y sub cambian de significado según rijan acusativo o ablativo","Los complementos circunstanciales de lugar se expresan con preposición excepto con nombres de ciudad"]'),
('latin', 'bachillerato', '{2}', '["El periodo ciceroniano organiza las ideas en oraciones complejas con subordinación múltiple","La prótasis presenta las circunstancias y condiciones antes de llegar a la idea principal","La apódosis contiene la afirmación central del periodo como conclusión de lo expuesto","Los incisos y las oraciones parentéticas enriquecen el periodo con matices y precisiones","Dominar la estructura del periodo es esencial para traducir los discursos y tratados de Cicerón"]'),
('latin', 'bachillerato', '{2}', '["Catón el Viejo fue el primer prosista latino importante con su tratado De agri cultura","Su obra defiende las virtudes rurales romanas frente a la corrupción de las costumbres helenizantes","Varrón compuso De lingua Latina un estudio gramatical y etimológico de la lengua latina","Varrón también escribió De re rustica un tratado de agricultura en forma de diálogo","La prosa técnica latina sentó las bases del ensayo científico y la literatura didáctica occidental"]'),
('latin', 'bachillerato', '{2}', '["Las guerras púnicas enfrentaron a Roma y Cartago por la hegemonía del Mediterráneo occidental","La primera guerra púnica se libró principalmente en el mar y en Sicilia entre 264 y 241 a.C.","Aníbal cruzó los Alpes con elefantes e invadió Italia en la segunda guerra púnica en 218 a.C.","Escipión el Africano derrotó a Aníbal en Zama en 202 a.C. asegurando la victoria romana","La tercera guerra púnica terminó con la destrucción total de Cartago en el 146 a.C."]'),
('latin', 'bachillerato', '{2}', '["El latín científico se utilizó como lengua internacional de la ciencia hasta el siglo XVIII","Linneo clasificó las especies biológicas en latín con su sistema binomial de nomenclatura","Newton escribió los Principia Mathematica en latín para que fueran accesibles a toda Europa","La terminología médica y jurídica actual conserva miles de términos latinos como corpus habeas y versus","El latín sigue siendo la lengua oficial de la Iglesia católica y del Estado del Vaticano"]'),
('latin', 'bachillerato', '{2}', '["El mito de Orfeo narra cómo el poeta bajó al inframundo para rescatar a su esposa Eurídice","Orfeo conmovió a Plutón y Prosérpina con su música y le permitieron llevarla de vuelta","La condición era no mirar atrás durante el ascenso pero Orfeo se volvió y perdió a Eurídice para siempre","Virgilio y Ovidio narraron este mito con variantes que enfatizan distintos aspectos del amor y la pérdida","El mito de Orfeo ha inspirado óperas pinturas y películas desde el Renacimiento hasta la actualidad"]'),
('latin', 'bachillerato', '{2}', '["El ejército romano se organizaba en legiones de unos cinco mil soldados divididos en cohortes","Cada legión estaba mandada por un legatus y los centuriones dirigían las centurias de ochenta hombres","Los legionarios construían campamentos fortificados cada noche durante las marchas militares","La disciplina militar romana era extraordinariamente estricta con castigos severos para los desertores","El ejército romano fue la fuerza militar más organizada y eficaz del mundo antiguo durante siglos"]'),
('latin', 'bachillerato', '{2}', '["Las interrogativas directas latinas se introducen con partículas como -ne num y nonne","La partícula -ne se añade al final de la primera palabra y no presupone ninguna respuesta","Num espera una respuesta negativa y nonne espera una respuesta afirmativa","Las interrogativas indirectas se introducen por pronombres o adverbios interrogativos con subjuntivo","Las interrogativas disyuntivas presentan dos alternativas unidas por utrum an o -ne an"]'),
('latin', 'bachillerato', '{2}', '["El mosaico romano decoraba los suelos de villas y edificios públicos con teselas de colores","Los frescos de Pompeya conservados por la erupción del Vesubio muestran la pintura romana en su esplendor","La escultura romana destacó en el retrato realista que captaba las facciones y el carácter del modelo","Los relieves narrativos como los de la Columna de Trajano documentan campañas militares con detalle","El arte romano adaptó modelos griegos y creó un lenguaje visual propio al servicio del poder imperial"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('literatura-universal', 'bachillerato', '{1}', '["La Ilíada de Homero narra la cólera de Aquiles durante el último año de la guerra de Troya","Aquiles se retira del combate ofendido por Agamenón y los griegos sufren graves derrotas","Patroclo viste la armadura de Aquiles para animar a los griegos y muere a manos de Héctor","Aquiles vuelve a la batalla y mata a Héctor arrastrando su cadáver alrededor de Troya","El poema concluye con los funerales de Héctor tras la súplica de su padre Príamo a Aquiles"]'),
('literatura-universal', 'bachillerato', '{1}', '["La Odisea narra el largo regreso de Ulises a Ítaca tras la guerra de Troya","Ulises supera peligros como el cíclope Polifemo las sirenas y la hechicera Circe","Penélope espera fielmente a su esposo tejiendo y destejiendo un sudario para rechazar pretendientes","Telémaco el hijo de Ulises parte en busca de noticias de su padre por los reinos griegos","Ulises regresa disfrazado de mendigo y mata a los pretendientes recuperando su trono y su familia"]'),
('literatura-universal', 'bachillerato', '{1}', '["Dante Alighieri comenzó a escribir la Divina Comedia hacia 1308 durante su exilio de Florencia","El poema narra un viaje por el Infierno el Purgatorio y el Paraíso en cien cantos de tercetos encadenados","Virgilio guía a Dante por el Infierno y el Purgatorio como símbolo de la razón humana","Beatriz guía a Dante por el Paraíso como símbolo de la gracia divina y el amor purificado","La Divina Comedia es considerada la obra cumbre de la literatura medieval y una de las mayores de todos los tiempos"]'),
('literatura-universal', 'bachillerato', '{1}', '["Boccaccio escribió el Decamerón hacia 1353 como colección de cien cuentos narrados en diez jornadas","Diez jóvenes huyen de la peste de Florencia y se entretienen contando historias ingeniosas","Los cuentos tratan del amor la astucia la fortuna y la crítica social con tono variado","El Decamerón inauguró la narrativa breve en prosa como género literario en lengua vernácula","La obra influyó en Chaucer Shakespeare y toda la tradición novelística europea posterior"]'),
('literatura-universal', 'bachillerato', '{1}', '["Shakespeare escribió Hamlet hacia 1601 como una de las mayores tragedias de la literatura universal","El príncipe Hamlet descubre que su tío Claudio asesinó a su padre para usurpar el trono","Hamlet duda entre la venganza y la reflexión pronunciando el célebre monólogo ser o no ser","La locura fingida de Hamlet y la real de Ofelia conducen a una cadena de muertes trágicas","La obra explora la duda la corrupción del poder y la fragilidad de la condición humana"]'),
('literatura-universal', 'bachillerato', '{1}', '["Molière dominó la comedia francesa del siglo XVII con obras que satirizaban los vicios sociales","El avaro retrata la obsesión enfermiza por el dinero del protagonista Harpagón","Tartufo denuncia la hipocresía religiosa de un impostor que engaña a un burgués crédulo","El enfermo imaginario ridiculiza a los médicos charlatanes y la credulidad del enfermo","Molière murió en escena representando su última obra en 1673 cumpliendo su vocación teatral"]'),
('literatura-universal', 'bachillerato', '{1}', '["El Romanticismo literario nació en Alemania e Inglaterra a finales del siglo XVIII","Los románticos alemanes como Novalis y los hermanos Schlegel exaltaron el sentimiento y la imaginación","Lord Byron Shelley y Keats representaron el Romanticismo inglés con poesía apasionada y rebelde","Victor Hugo lideró el Romanticismo francés con novelas como Los miserables y Nuestra Señora de París","El Romanticismo reivindicó la libertad individual la naturaleza salvaje y el genio creador del artista"]'),
('literatura-universal', 'bachillerato', '{1}', '["El Realismo literario del siglo XIX pretendió reflejar la sociedad tal como era sin idealizaciones","Balzac retrató la sociedad francesa en su monumental Comedia Humana con decenas de novelas","Flaubert perfeccionó la técnica realista con Madame Bovary y su estilo impersonal y preciso","Dickens denunció las desigualdades de la Inglaterra victoriana en Oliver Twist y David Copperfield","Dostoievski exploró las profundidades psicológicas del ser humano en Crimen y castigo y Los hermanos Karamázov"]'),
('literatura-universal', 'bachillerato', '{1}', '["Tolstói escribió Guerra y paz como una epopeya que abarca la sociedad rusa durante las guerras napoleónicas","Anna Karénina explora el amor prohibido y la presión social en la aristocracia rusa del XIX","Chéjov revolucionó el cuento moderno con relatos breves de atmósfera sutil y finales abiertos","Las obras teatrales de Chéjov como El jardín de los cerezos captan la melancolía del cambio social","La literatura rusa del XIX alcanzó una universalidad que la convirtió en referencia mundial"]'),
('literatura-universal', 'bachillerato', '{1}', '["Baudelaire publicó Las flores del mal en 1857 inaugurando la poesía moderna en Francia","Rimbaud escribió toda su obra poética antes de los veinte años y luego abandonó la literatura","Mallarmé llevó la poesía simbolista al límite de la abstracción y la musicalidad pura","Verlaine proclamó la música ante todo como principio de su arte poético","El simbolismo francés influyó decisivamente en la poesía del siglo XX desde el modernismo hasta las vanguardias"]'),
('literatura-universal', 'bachillerato', '{1}', '["Kafka publicó La metamorfosis en 1915 narrando la transformación de Gregorio Samsa en insecto","El proceso presenta a un hombre acusado por un tribunal misterioso sin conocer su delito","El castillo describe los intentos fallidos de un agrimensor por acceder a una autoridad inalcanzable","La obra de Kafka expresa la alienación la burocracia absurda y la culpa sin causa del individuo moderno","El adjetivo kafkiano se ha incorporado al lenguaje común para describir situaciones absurdas y opresivas"]'),
('literatura-universal', 'bachillerato', '{1}', '["Virginia Woolf experimentó con el flujo de conciencia en La señora Dalloway publicada en 1925","Al faro explora las relaciones familiares y el paso del tiempo a través de impresiones subjetivas","Orlando narra la vida de un personaje que cambia de sexo a lo largo de cuatro siglos","Una habitación propia es un ensayo fundamental sobre la mujer y la creación literaria","Woolf es considerada una de las renovadoras más importantes de la narrativa del siglo XX"]'),
('literatura-universal', 'bachillerato', '{1}', '["El teatro del absurdo surgió en los años cincuenta cuestionando la lógica y el sentido del lenguaje","Esperando a Godot de Beckett presenta a dos personajes que esperan a alguien que nunca llega","Ionesco mostró la incomunicación humana en La cantante calva con diálogos vacíos de significado","Las sillas de Ionesco llena un escenario de sillas vacías para un público que no existe","El teatro del absurdo expresó la crisis de sentido de la civilización occidental tras las guerras mundiales"]'),
('literatura-universal', 'bachillerato', '{1}', '["El realismo mágico latinoamericano fusionó lo cotidiano con lo maravilloso como parte natural de la vida","García Márquez publicó Cien años de soledad en 1967 fundando Macondo como espacio mítico universal","Borges creó mundos laberínticos de bibliotecas infinitas y tiempos circulares en sus Ficciones","Cortázar experimentó con la estructura narrativa en Rayuela permitiendo múltiples órdenes de lectura","El boom latinoamericano de los sesenta y setenta proyectó la literatura hispanoamericana al mundo entero"]'),
('literatura-universal', 'bachillerato', '{1}', '["Petrarca compuso el Cancionero como colección de sonetos y canciones dedicados a Laura","Sus sonetos establecieron el modelo de la poesía amorosa europea durante tres siglos","El petrarquismo se difundió por Italia España Francia e Inglaterra con imitadores y seguidores","Petrarca es considerado el primer humanista por su recuperación de los clásicos latinos","La idealización del amor y la belleza en Petrarca influyó en toda la lírica renacentista"]'),
('literatura-universal', 'bachillerato', '{1}', '["Las mil y una noches reúnen cuentos de tradición árabe persa e india enmarcados por Scheherezade","Scheherezade narra historias cada noche para salvar su vida y aplazar su ejecución por el sultán","Los cuentos de Aladino Simbad y Alí Babá son los más conocidos de esta colección milenaria","La estructura de relatos enmarcados dentro de otros relatos creó un modelo narrativo innovador","Las mil y una noches influyeron en la literatura europea desde el siglo XVIII a través de traducciones"]'),
('literatura-universal', 'bachillerato', '{1}', '["La poesía de Emily Dickinson permaneció casi toda inédita hasta después de su muerte en 1886","Sus poemas breves e intensos exploran la muerte la inmortalidad la naturaleza y la fe","Walt Whitman publicó Hojas de hierba en 1855 celebrando la democracia americana y el cuerpo humano","Whitman creó el verso libre en inglés rompiendo con las formas métricas tradicionales","Dickinson y Whitman representan los dos polos de la poesía estadounidense del siglo XIX"]'),
('literatura-universal', 'bachillerato', '{1}', '["El naturalismo de Zola aplicó el método científico a la novela estudiando la herencia y el medio","La serie de los Rougon-Macquart abarca veinte novelas que retratan la sociedad francesa del Segundo Imperio","Germinal denuncia las condiciones inhumanas de los mineros franceses del siglo XIX","Zola intervino en el caso Dreyfus con su artículo Yo acuso defendiendo al oficial injustamente condenado","El naturalismo influyó en novelistas de todo el mundo desde Clarín en España hasta Eça de Queirós en Portugal"]'),
('literatura-universal', 'bachillerato', '{1}', '["T.S. Eliot publicó La tierra baldía en 1922 como poema fragmentario sobre la crisis de la civilización","Ezra Pound promovió el imagismo y las vanguardias poéticas anglosajonas a principios del siglo XX","W.B. Yeats fusionó el simbolismo con el misticismo celta en su poesía irlandesa","La generación perdida de Hemingway y Fitzgerald retrató el desencanto de la posguerra americana","Hemingway desarrolló un estilo narrativo depurado y sobrio que influyó en la prosa mundial del siglo XX"]'),
('literatura-universal', 'bachillerato', '{1}', '["Cervantes publicó el Quijote en 1605 creando la primera novela moderna de la literatura universal","La novela establece un diálogo entre ficción y realidad con un protagonista que confunde ambas","Laurence Sterne publicó Tristram Shandy en 1759 anticipando las técnicas experimentales del siglo XX","La novela del XVIII con Richardson Fielding y Defoe consolidó el género como forma literaria dominante","Robinson Crusoe de Defoe fundó el mito del hombre solitario que reconstruye la civilización desde cero"]'),
('literatura-universal', 'bachillerato', '{1}', '["Las tragedias griegas se representaban en festivales religiosos en honor al dios Dioniso","Esquilo introdujo el segundo actor y elevó la tragedia a gran arte con la Orestíada","Sófocles añadió el tercer actor y perfeccionó la estructura dramática con Antígona y Edipo Rey","Eurípides humanizó a los personajes trágicos y cuestionó las tradiciones con Medea y Las bacantes","La comedia griega de Aristófanes satirizó la política la guerra y la sociedad ateniense con humor mordaz"]'),
('literatura-universal', 'bachillerato', '{1}', '["Orwell publicó 1984 en 1949 como distopía sobre un Estado totalitario que controla el pensamiento","Huxley anticipó en Un mundo feliz de 1932 una sociedad alienada por el placer y la tecnología","Bradbury imaginó en Fahrenheit 451 un futuro donde los libros son quemados por el Estado","Atwood exploró la opresión de género en una teocracia en El cuento de la criada","La literatura distópica advierte sobre los peligros de la pérdida de libertad y el control social"]'),
('literatura-universal', 'bachillerato', '{1}', '["El Cantar de los Nibelungos es la gran epopeya germánica medieval compuesta hacia 1200","Sigfrido mata al dragón Fafnir y se baña en su sangre haciéndose invulnerable salvo en un punto","Krimilda se casa con Sigfrido pero Hagen lo asesina a traición en una cacería","Krimilda trama durante años su venganza contra los burgundios hasta provocar una masacre final","El poema inspiró a Wagner para componer la tetralogía operística El anillo del Nibelungo"]'),
('literatura-universal', 'bachillerato', '{1}', '["Chaucer escribió los Cuentos de Canterbury hacia 1390 como retrato de la sociedad inglesa medieval","Treinta peregrinos viajan a Canterbury y cuentan historias que reflejan todas las clases sociales","Los cuentos abarcan géneros diversos desde el romance caballeresco hasta el fabliaux obsceno","Chaucer escribió en inglés medio elevándolo a lengua literaria frente al latín y el francés","Los Cuentos de Canterbury son la obra fundacional de la literatura inglesa"]'),
('literatura-universal', 'bachillerato', '{1}', '["Thomas Mann publicó La montaña mágica en 1924 como novela filosófica ambientada en un sanatorio suizo","Hermann Hesse exploró la búsqueda espiritual en El lobo estepario y Siddharta","Günter Grass revisó la historia alemana del siglo XX en El tambor de hojalata","Heinrich Böll retrató la posguerra alemana con un realismo crítico y humanista","La narrativa alemana del siglo XX reflexionó profundamente sobre la culpa la memoria y la identidad"]'),
('literatura-universal', 'bachillerato', '{1}', '["Montaigne inventó el ensayo moderno con sus Essais publicados a partir de 1580","El ensayo como género literario permite la reflexión libre sobre cualquier tema sin estructura fija","La enciclopedia ilustrada de Diderot representó el proyecto de compilar todo el saber humano","Voltaire usó el cuento filosófico como Cándido para criticar el optimismo y la intolerancia","La Ilustración francesa convirtió la literatura en instrumento de crítica social y difusión del saber"]'),
('literatura-universal', 'bachillerato', '{1}', '["Ibsen renovó el teatro europeo con dramas realistas que cuestionaban la moral burguesa","Casa de muñecas de 1879 escandalizó al público mostrando a una mujer que abandona su hogar","Strindberg radicalizó el teatro con obras expresionistas como La señorita Julia","Pirandello cuestionó la identidad y la realidad teatral en Seis personajes en busca de autor","El teatro moderno europeo evolucionó desde el realismo hacia el expresionismo y la metateatralidad"]'),
('literatura-universal', 'bachillerato', '{1}', '["La narrativa africana contemporánea emergió con las independencias de la segunda mitad del siglo XX","Chinua Achebe publicó Todo se desmorona en 1958 retratando el impacto colonial en la cultura igbo","Wole Soyinka recibió el primer Nobel africano de literatura en 1986 por su obra teatral y poética","Ngugi wa Thiongo abandonó el inglés para escribir en kikuyu como acto de resistencia cultural","La literatura africana ha aportado voces esenciales al panorama literario mundial del siglo XXI"]'),
('literatura-universal', 'bachillerato', '{1}', '["El Werther de Goethe de 1774 inauguró la novela sentimental europea con un protagonista suicida","La obra provocó una oleada de suicidios por imitación conocida como efecto Werther","Mary Shelley publicó Frankenstein en 1818 creando la novela de ciencia ficción moderna","Edgar Allan Poe fundó el relato de terror psicológico y la novela policiaca con Los crímenes de la calle Morgue","El Romanticismo exploró los lados oscuros del alma humana abriendo camino a la literatura fantástica y de horror"]'),
('literatura-universal', 'bachillerato', '{1}', '["El haiku japonés es un poema de tres versos que capta un instante de la naturaleza con economía extrema","Bashō perfeccionó el haiku en el siglo XVII como forma de expresión zen y contemplativa","La poesía china clásica de Li Bai y Du Fu influyó en los poetas imagistas occidentales","El teatro Noh japonés combina danza música y texto con una estética de la contención","Las literaturas orientales han enriquecido la tradición occidental aportando nuevas formas y sensibilidades"]'),
('literatura-universal', 'bachillerato', '{1}', '["Proust comenzó a publicar En busca del tiempo perdido en 1913 con Por el camino de Swann","La novela explora la memoria involuntaria desencadenada por sensaciones como el sabor de una magdalena","A lo largo de siete volúmenes Proust reconstruye el mundo aristocrático y artístico del París de su época","El narrador busca recuperar el tiempo perdido mediante la escritura como forma de salvación","La obra de Proust es una de las cumbres de la narrativa moderna por su análisis del tiempo y la conciencia"]'),
('literatura-universal', 'bachillerato', '{1}', '["William Faulkner creó el condado ficticio de Yoknapatawpha como microcosmos del sur de Estados Unidos","El ruido y la furia de 1929 narra la decadencia de una familia sureña con múltiples puntos de vista","Faulkner experimentó con el tiempo narrativo la fragmentación y el monólogo interior","Steinbeck denunció la miseria de los trabajadores agrícolas en Las uvas de la ira durante la Gran Depresión","La narrativa estadounidense del siglo XX se caracteriza por su diversidad técnica y su compromiso social"]'),
('literatura-universal', 'bachillerato', '{1}', '["La Eneida de Virgilio vincula la fundación de Roma con la caída de Troya creando una epopeya nacional","El Orlando furioso de Ariosto renovó la épica renacentista con humor fantasía y estructura laberíntica","El Paraíso perdido de Milton narra la rebelión de Satanás y la caída del hombre en verso épico inglés","Los Lusiadas de Camões celebran la historia portuguesa y los descubrimientos marítimos como epopeya nacional","La épica literaria evolucionó desde el modelo homérico hacia formas cada vez más personales y filosóficas"]'),
('literatura-universal', 'bachillerato', '{1}', '["Neruda publicó Veinte poemas de amor y una canción desesperada en 1924 como lírica amorosa juvenil","Vallejo expresó el dolor humano y la solidaridad en Trilce y España aparta de mí este cáliz","Octavio Paz exploró la identidad mexicana y la poesía como conocimiento en El laberinto de la soledad y Piedra de sol","Gabriela Mistral fue la primera latinoamericana en recibir el Nobel de Literatura en 1945","La poesía hispanoamericana del siglo XX alcanzó una voz propia reconocida universalmente"]'),
('literatura-universal', 'bachillerato', '{1}', '["Jane Austen retrató la sociedad rural inglesa del siglo XIX con ironía y agudeza psicológica","Orgullo y prejuicio de 1813 narra el enfrentamiento y la atracción entre Elizabeth Bennet y el señor Darcy","Las hermanas Brontë crearon mundos apasionados con Cumbres borrascosas y Jane Eyre","George Eliot exploró la vida provincial y las ambiciones humanas en Middlemarch","Las novelistas británicas del XIX demostraron que la narrativa femenina podía alcanzar la máxima excelencia literaria"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('historia-mundo', 'bachillerato', '{1}', '["La Revolución Industrial comenzó en Inglaterra a mediados del siglo XVIII con la máquina de vapor","La mecanización de la industria textil multiplicó la producción y transformó el trabajo manual","El ferrocarril revolucionó el transporte de mercancías y personas a partir de la década de 1830","La industrialización se extendió a Bélgica Francia Alemania y Estados Unidos a lo largo del XIX","Las condiciones laborales extremas generaron el movimiento obrero y las primeras organizaciones sindicales"]'),
('historia-mundo', 'bachillerato', '{1}', '["La independencia de Estados Unidos se declaró el 4 de julio de 1776 rompiendo con Gran Bretaña","George Washington lideró el ejército continental hasta la victoria definitiva en Yorktown en 1781","La Constitución de 1787 estableció una república federal con separación de poderes","La Carta de Derechos de 1791 garantizó las libertades individuales como las primeras diez enmiendas","La independencia americana inspiró los movimientos liberales y revolucionarios en Europa y América Latina"]'),
('historia-mundo', 'bachillerato', '{1}', '["Napoleón Bonaparte se coronó emperador de Francia en 1804 extendiendo su poder por Europa","Las guerras napoleónicas reconfiguraron el mapa europeo con victorias como Austerlitz y Jena","La invasión de Rusia en 1812 fue el principio del fin con la destrucción de la Grande Armée","Las potencias europeas derrotaron definitivamente a Napoleón en Waterloo en junio de 1815","El Congreso de Viena restauró las monarquías absolutas y redibujó las fronteras europeas"]'),
('historia-mundo', 'bachillerato', '{1}', '["Las revoluciones de 1848 estallaron simultáneamente en Francia Alemania Italia y el Imperio Austríaco","Los revolucionarios demandaban constituciones liberales libertades civiles y derechos nacionales","La revolución de febrero en Francia derrocó a Luis Felipe e instauró la Segunda República","Los movimientos nacionalistas italianos y alemanes buscaron la unificación de sus territorios","La mayoría de las revoluciones fueron aplastadas pero sentaron las bases de los cambios posteriores"]'),
('historia-mundo', 'bachillerato', '{1}', '["Bismarck unificó Alemania mediante tres guerras contra Dinamarca Austria y Francia","La victoria sobre Francia en 1870 permitió la proclamación del Imperio Alemán en Versalles","La unificación italiana se completó en 1870 con la toma de Roma como capital del nuevo reino","Cavour dirigió la diplomacia piamontesa y Garibaldi lideró la expedición de los Mil en el sur","Las unificaciones de Alemania e Italia transformaron el equilibrio de poder en Europa"]'),
('historia-mundo', 'bachillerato', '{1}', '["El imperialismo europeo del siglo XIX se extendió por África Asia y el Pacífico","La Conferencia de Berlín de 1884 repartió África entre las potencias europeas sin consultar a los africanos","Gran Bretaña dominó la India como joya de la corona de su imperio colonial","Francia colonizó gran parte del norte y oeste de África y la península de Indochina","La rivalidad colonial entre las potencias europeas fue una de las causas de la Primera Guerra Mundial"]'),
('historia-mundo', 'bachillerato', '{1}', '["La Revolución Rusa de febrero de 1917 derrocó al zar Nicolás II tras siglos de autocracia","El gobierno provisional de Kerensky no logró estabilizar el país ni poner fin a la guerra","Lenin y los bolcheviques tomaron el poder en la revolución de octubre de 1917","La guerra civil rusa enfrentó al Ejército Rojo contra el Ejército Blanco hasta 1922","La Unión Soviética se constituyó en 1922 como el primer Estado socialista del mundo"]'),
('historia-mundo', 'bachillerato', '{1}', '["El periodo de entreguerras estuvo marcado por la inestabilidad económica y el auge de los extremismos","La hiperinflación en Alemania en 1923 destruyó los ahorros de la clase media y generó caos social","Mussolini instauró el fascismo en Italia tras la Marcha sobre Roma en octubre de 1922","Hitler fue nombrado canciller de Alemania en enero de 1933 e instauró la dictadura nazi","Los totalitarismos de entreguerras destruyeron la democracia liberal en gran parte de Europa"]'),
('historia-mundo', 'bachillerato', '{1}', '["La Segunda Guerra Mundial comenzó con la invasión alemana de Polonia el 1 de septiembre de 1939","La guerra relámpago nazi conquistó Francia en seis semanas en la primavera de 1940","La Operación Barbarroja invadió la Unión Soviética en junio de 1941 abriendo el frente oriental","El desembarco de Normandía en junio de 1944 abrió un segundo frente que aceleró la derrota alemana","Las bombas atómicas sobre Hiroshima y Nagasaki en agosto de 1945 forzaron la rendición de Japón"]'),
('historia-mundo', 'bachillerato', '{1}', '["El Holocausto fue el genocidio sistemático de seis millones de judíos por el régimen nazi","Las leyes de Núremberg de 1935 privaron a los judíos de sus derechos de ciudadanía","La Noche de los Cristales Rotos en noviembre de 1938 marcó una escalada de violencia antisemita","Los campos de exterminio como Auschwitz fueron diseñados para el asesinato industrial masivo","Los juicios de Núremberg de 1945 juzgaron a los responsables nazis por crímenes contra la humanidad"]'),
('historia-mundo', 'bachillerato', '{1}', '["La ONU se fundó en 1945 para mantener la paz y la seguridad internacional tras la guerra","La Declaración Universal de los Derechos Humanos se aprobó en 1948 como marco ético global","El Plan Marshall de 1948 proporcionó ayuda económica americana para reconstruir la Europa devastada","La creación de la OTAN en 1949 organizó la defensa occidental frente a la amenaza soviética","El nuevo orden internacional de posguerra se construyó sobre instituciones multilaterales y alianzas"]'),
('historia-mundo', 'bachillerato', '{1}', '["La Guerra de Corea de 1950 a 1953 fue el primer conflicto armado directo de la Guerra Fría","La guerra de Vietnam enfrentó al sur apoyado por EEUU contra el norte comunista durante dos décadas","La intervención americana en Vietnam generó un masivo movimiento pacifista en Estados Unidos","La caída de Saigón en 1975 marcó la derrota estadounidense y la reunificación de Vietnam","Las guerras de Corea y Vietnam demostraron los límites del poder militar en conflictos ideológicos"]'),
('historia-mundo', 'bachillerato', '{1}', '["China vivió una guerra civil entre nacionalistas y comunistas interrumpida por la invasión japonesa","Mao Zedong proclamó la República Popular China el 1 de octubre de 1949 tras vencer a los nacionalistas","El Gran Salto Adelante de 1958 intentó industrializar China rápidamente causando una gran hambruna","La Revolución Cultural de 1966 persiguió a intelectuales y opositores con violencia ideológica","Tras la muerte de Mao en 1976 Deng Xiaoping introdujo reformas económicas que transformaron China"]'),
('historia-mundo', 'bachillerato', '{1}', '["El movimiento por los derechos civiles en EEUU luchó contra la segregación racial desde los años cincuenta","Rosa Parks se negó a ceder su asiento en un autobús en Montgomery en 1955 iniciando un boicot histórico","Martin Luther King lideró la marcha sobre Washington en 1963 con su discurso Tengo un sueño","La Ley de Derechos Civiles de 1964 prohibió la discriminación racial en lugares públicos y empleo","El asesinato de King en 1968 no detuvo el avance hacia la igualdad legal de los afroamericanos"]'),
('historia-mundo', 'bachillerato', '{1}', '["El Estado de Israel se proclamó en 1948 provocando la primera guerra árabe-israelí","La guerra de los Seis Días en 1967 amplió el territorio israelí con la ocupación de Cisjordania y Gaza","La guerra del Yom Kippur en 1973 sorprendió a Israel y provocó la crisis del petróleo mundial","Los Acuerdos de Camp David en 1978 establecieron la paz entre Egipto e Israel","El conflicto palestino-israelí sigue sin resolverse generando inestabilidad en Oriente Medio"]'),
('historia-mundo', 'bachillerato', '{1}', '["La carrera espacial comenzó cuando la URSS lanzó el Sputnik el primer satélite artificial en 1957","Yuri Gagarin fue el primer ser humano en viajar al espacio en abril de 1961","Estados Unidos respondió con el programa Apolo que llevó a Neil Armstrong a la Luna en 1969","La carrera espacial fue una competición tecnológica y propagandística entre las dos superpotencias","La cooperación espacial sustituyó a la rivalidad con la Estación Espacial Internacional en los noventa"]'),
('historia-mundo', 'bachillerato', '{1}', '["La revolución iraní de 1979 derrocó al shah e instauró una república islámica bajo el ayatolá Jomeini","La guerra entre Irán e Irak se prolongó de 1980 a 1988 con cientos de miles de víctimas","La invasión iraquí de Kuwait en 1990 provocó la Guerra del Golfo liderada por Estados Unidos","Los atentados del 11 de septiembre de 2001 desencadenaron la guerra contra el terrorismo","La invasión de Irak en 2003 generó una prolongada inestabilidad en todo Oriente Medio"]'),
('historia-mundo', 'bachillerato', '{1}', '["El apartheid en Sudáfrica impuso la segregación racial desde 1948 hasta 1991","Nelson Mandela fue encarcelado durante veintisiete años por su lucha contra el régimen racista","Las sanciones internacionales y la resistencia interna presionaron al gobierno para negociar reformas","Mandela fue liberado en 1990 y las primeras elecciones multirraciales se celebraron en 1994","Mandela se convirtió en presidente de Sudáfrica y en símbolo mundial de la reconciliación"]'),
('historia-mundo', 'bachillerato', '{1}', '["La Unión Europea tiene sus orígenes en la Comunidad Europea del Carbón y del Acero creada en 1951","El Tratado de Roma de 1957 creó la Comunidad Económica Europea con seis países fundadores","El Acta Única Europea de 1986 impulsó el mercado interior eliminando barreras comerciales","El Tratado de Maastricht de 1992 creó la Unión Europea e introdujo la ciudadanía común","La ampliación hacia el este en 2004 incorporó a diez nuevos países consolidando la unificación europea"]'),
('historia-mundo', 'bachillerato', '{1}', '["Gorbachov introdujo la perestroika y la glásnost para reformar la Unión Soviética en los años ochenta","Las reformas liberalizaron la economía y la política pero desencadenaron fuerzas centrífugas","Las repúblicas bálticas declararon su independencia desafiando al poder central soviético","El golpe de Estado fallido de agosto de 1991 aceleró la desintegración de la URSS","La Unión Soviética se disolvió oficialmente el 25 de diciembre de 1991 poniendo fin a la Guerra Fría"]'),
('historia-mundo', 'bachillerato', '{1}', '["La Revolución Francesa abolió los privilegios feudales en la noche del 4 de agosto de 1789","La Declaración de los Derechos del Hombre estableció la igualdad ante la ley y la soberanía nacional","La ejecución de Luis XVI en enero de 1793 radicalizó la revolución y provocó la guerra con Europa","El Directorio de 1795 intentó estabilizar la república pero fue derribado por Napoleón en 1799","La Revolución Francesa transformó las bases políticas y sociales de la Europa contemporánea"]'),
('historia-mundo', 'bachillerato', '{1}', '["Las independencias latinoamericanas comenzaron a principios del siglo XIX inspiradas por las revoluciones atlánticas","Simón Bolívar liberó Venezuela Colombia Ecuador Perú y Bolivia del dominio español","José de San Martín lideró la independencia de Argentina Chile y contribuyó a la del Perú","México logró su independencia en 1821 tras una larga guerra iniciada por el cura Hidalgo en 1810","Brasil se independizó pacíficamente de Portugal en 1822 convirtiéndose en un imperio bajo Pedro I"]'),
('historia-mundo', 'bachillerato', '{1}', '["El Antiguo Régimen se basaba en una sociedad estamental con privilegios para la nobleza y el clero","El Tercer Estado que representaba al noventa y cinco por ciento de la población carecía de privilegios","Los filósofos ilustrados como Voltaire y Montesquieu criticaron el absolutismo y la intolerancia","La crisis financiera de la monarquía francesa obligó a convocar los Estados Generales en 1789","La transformación del Tercer Estado en Asamblea Nacional marcó el inicio de la revolución política"]'),
('historia-mundo', 'bachillerato', '{1}', '["La crisis del petróleo de 1973 multiplicó los precios del crudo sacudiendo las economías occidentales","Los países productores de la OPEP usaron el petróleo como arma política durante la guerra del Yom Kippur","La segunda crisis del petróleo en 1979 coincidió con la revolución iraní y la guerra Irán-Irak","Las crisis energéticas pusieron fin a los treinta años de crecimiento económico de posguerra","Los gobiernos occidentales respondieron con políticas de austeridad y liberalización económica"]'),
('historia-mundo', 'bachillerato', '{1}', '["La Revolución Industrial transformó la agricultura con nuevas técnicas de rotación y maquinaria","El éxodo rural trasladó a millones de campesinos a las ciudades industriales del siglo XIX","Las condiciones de vida en las fábricas y barrios obreros eran insalubres y la jornada laboral excesiva","Los sindicatos y los partidos socialistas lucharon por los derechos laborales y el sufragio universal","El movimiento obrero consiguió progresivamente la reducción de la jornada laboral y la legislación social"]'),
('historia-mundo', 'bachillerato', '{1}', '["La Primera Guerra Mundial fue un conflicto total que movilizó todos los recursos de las naciones beligerantes","La tecnología militar introdujo ametralladoras gases tóxicos tanques y aviones por primera vez","El frente occidental se estancó en una guerra de trincheras con enormes bajas y avances mínimos","El frente oriental fue más móvil pero igualmente devastador para los imperios ruso y austrohúngaro","La guerra causó más de diez millones de muertos militares y transformó la sociedad europea irreversiblemente"]'),
('historia-mundo', 'bachillerato', '{1}', '["Los catorce puntos de Wilson propusieron una paz justa basada en la autodeterminación de los pueblos","El Tratado de Versalles impuso a Alemania reparaciones de guerra cesiones territoriales y limitaciones militares","Los imperios austrohúngaro otomano y ruso se desintegraron creando nuevos Estados nacionales","La Sociedad de Naciones se fundó en 1920 como primer organismo internacional para mantener la paz","La fragilidad del orden de posguerra y el resentimiento alemán sembraron las semillas de un nuevo conflicto"]'),
('historia-mundo', 'bachillerato', '{1}', '["El crack de 1929 en Wall Street provocó la mayor crisis económica del siglo XX","Los bancos quebraron el comercio internacional se desplomó y el desempleo alcanzó cifras récord","El New Deal de Roosevelt aplicó políticas de intervención estatal para reactivar la economía americana","Keynes propuso que el Estado debía intervenir con gasto público para combatir el desempleo","La Gran Depresión demostró que el libre mercado sin regulación podía generar catástrofes económicas"]'),
('historia-mundo', 'bachillerato', '{1}', '["Gandhi lideró el movimiento independentista indio con la estrategia de la no violencia y la desobediencia civil","La marcha de la sal en 1930 desafió el monopolio británico y movilizó a millones de indios","La partición de la India en 1947 creó los Estados de India y Pakistán con enormes desplazamientos","Gandhi fue asesinado en enero de 1948 por un nacionalista hindú extremista","El modelo gandhiano de resistencia pacífica inspiró movimientos sociales en todo el mundo"]'),
('historia-mundo', 'bachillerato', '{1}', '["La globalización se aceleró a finales del siglo XX con la liberalización del comercio y las comunicaciones","Internet transformó la economía la comunicación y las relaciones sociales a partir de los años noventa","La caída del comunismo soviético dejó a Estados Unidos como única superpotencia global","China se convirtió en potencia económica mundial tras décadas de crecimiento acelerado","Los desafíos del siglo XXI incluyen el cambio climático la desigualdad y las tensiones geopolíticas"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('historia-espana', 'bachillerato', '{2}', '["Los Reyes Católicos unificaron los reinos de Castilla y Aragón mediante su matrimonio en 1469","Conquistaron Granada en 1492 poniendo fin a ocho siglos de presencia musulmana en la Península","Financiaron el viaje de Colón que descubrió América el 12 de octubre de 1492","Expulsaron a los judíos y establecieron la Inquisición como instrumento de unidad religiosa","Su reinado sentó las bases del Estado moderno español con instituciones centralizadas"]'),
('historia-espana', 'bachillerato', '{2}', '["Las Cortes de Cádiz se reunieron en 1810 para gobernar España durante la invasión napoleónica","Diputados liberales y absolutistas debatieron el modelo de Estado en medio de la guerra","La Constitución de 1812 proclamó la soberanía nacional la división de poderes y los derechos individuales","Estableció la monarquía constitucional el sufragio masculino indirecto y la libertad de imprenta","La Pepa como fue conocida se convirtió en referente del liberalismo europeo y latinoamericano"]'),
('historia-espana', 'bachillerato', '{2}', '["Fernando VII regresó a España en 1814 y abolió la Constitución de Cádiz restaurando el absolutismo","El Trienio Liberal de 1820 a 1823 restableció brevemente la Constitución tras el pronunciamiento de Riego","Los Cien Mil Hijos de San Luis intervención francesa restauraron el absolutismo fernandino en 1823","La Década Ominosa de 1823 a 1833 fue un periodo de represión contra los liberales","La cuestión sucesoria entre isabelinos y carlistas provocó una guerra civil a la muerte de Fernando VII"]'),
('historia-espana', 'bachillerato', '{2}', '["La Primera Guerra Carlista enfrentó a los partidarios de Carlos María Isidro contra los de Isabel II","Los carlistas defendían el absolutismo el foralismo y el catolicismo tradicional","Los isabelinos apoyaban el liberalismo y la monarquía constitucional bajo la regencia de María Cristina","Espartero se convirtió en regente tras la victoria liberal en el Convenio de Vergara de 1839","Las guerras carlistas marcaron la primera mitad del siglo XIX español con tres conflictos sucesivos"]'),
('historia-espana', 'bachillerato', '{2}', '["El reinado de Isabel II osciló entre el liberalismo moderado y el progresista con frecuentes pronunciamientos","La Constitución moderada de 1845 restringió el sufragio y reforzó el poder de la Corona","El Bienio Progresista de 1854 a 1856 introdujo reformas como la desamortización de Madoz","La revolución Gloriosa de septiembre de 1868 derrocó a Isabel II que marchó al exilio","El Sexenio Democrático de 1868 a 1874 experimentó con la monarquía democrática y la república"]'),
('historia-espana', 'bachillerato', '{2}', '["Amadeo I de Saboya reinó brevemente entre 1871 y 1873 sin lograr estabilizar el país","La Primera República se proclamó en febrero de 1873 pero duró menos de dos años","La República atravesó cuatro presidentes en once meses entre federalismo e inestabilidad","El cantonalismo fragmentó el país con insurrecciones locales que reclamaban autonomía","El golpe de Pavía en enero de 1874 puso fin a la República y preparó la restauración borbónica"]'),
('historia-espana', 'bachillerato', '{2}', '["Cánovas del Castillo diseñó el sistema de la Restauración con Alfonso XII como rey desde 1874","La Constitución de 1876 estableció un sistema liberal doctrinario con soberanía compartida entre rey y Cortes","El turnismo pacífico alternaba en el poder al Partido Conservador de Cánovas y al Liberal de Sagasta","El caciquismo y el pucherazo manipulaban las elecciones para garantizar la alternancia pactada","El sistema funcionó con estabilidad aparente pero excluyó a amplios sectores sociales de la participación política"]'),
('historia-espana', 'bachillerato', '{2}', '["El Desastre del 98 supuso la pérdida de Cuba Puerto Rico y Filipinas las últimas colonias españolas","La derrota militar ante Estados Unidos provocó una profunda crisis de identidad nacional","Los regeneracionistas como Joaquín Costa denunciaron el atraso de España y pidieron modernización","La Generación del 98 expresó en literatura la angustia por el declive nacional","El Desastre aceleró la crisis del sistema de la Restauración y el auge de los nacionalismos periféricos"]'),
('historia-espana', 'bachillerato', '{2}', '["La crisis de la Restauración se agravó con la Semana Trágica de Barcelona en 1909","La guerra de Marruecos provocó el descontento popular y la crisis del Annual en 1921","El movimiento obrero creció con la CNT anarquista y la UGT socialista como principales sindicatos","Los nacionalismos catalán y vasco se fortalecieron reclamando autonomía política","La inestabilidad política social y militar preparó el terreno para la dictadura de Primo de Rivera"]'),
('historia-espana', 'bachillerato', '{2}', '["Primo de Rivera dio un golpe de Estado en septiembre de 1923 con el apoyo de Alfonso XIII","La dictadura suspendió la Constitución disolvió las Cortes y prohibió los partidos políticos","El Directorio Militar inicial dio paso a un Directorio Civil con políticas de obras públicas","La oposición creciente de intelectuales militares y políticos debilitó la dictadura","Primo de Rivera dimitió en enero de 1930 y su caída arrastró a la monarquía de Alfonso XIII"]'),
('historia-espana', 'bachillerato', '{2}', '["Las elecciones municipales del 12 de abril de 1931 dieron la victoria republicana en las grandes ciudades","Alfonso XIII partió al exilio y se proclamó la Segunda República el 14 de abril de 1931","El Bienio Reformista de 1931 a 1933 aprobó la Constitución la reforma agraria y el Estatuto catalán","El Bienio Radical-Cedista de 1933 a 1936 frenó las reformas y reprimió la revolución de Asturias de 1934","El Frente Popular ganó las elecciones de febrero de 1936 en un clima de polarización extrema"]'),
('historia-espana', 'bachillerato', '{2}', '["La Constitución de 1931 estableció un Estado laico democrático y descentralizado","Reconoció el sufragio femenino la separación Iglesia-Estado y los derechos sociales","La reforma agraria pretendió redistribuir la tierra de los grandes latifundios entre los jornaleros","La cuestión religiosa provocó fuertes tensiones entre laicistas y católicos conservadores","La reforma militar intentó modernizar y reducir el ejército eliminando el exceso de oficiales"]'),
('historia-espana', 'bachillerato', '{2}', '["El alzamiento militar del 18 de julio de 1936 fracasó como golpe rápido y derivó en guerra civil","España quedó dividida en dos zonas: la republicana en el este y sur y la sublevada en el norte y oeste","La ayuda alemana e italiana apoyó a los sublevados mientras la URSS y las Brigadas Internacionales al bando republicano","La batalla del Ebro en 1938 fue la más larga y sangrienta de la guerra y agotó al ejército republicano","Madrid cayó el 28 de marzo de 1939 y Franco declaró el fin de la guerra el 1 de abril"]'),
('historia-espana', 'bachillerato', '{2}', '["Las causas de la Guerra Civil incluyen la polarización política la cuestión agraria y los conflictos sociales","La conspiración militar se gestó entre generales descontentos con el gobierno del Frente Popular","La violencia política de la primavera de 1936 con asesinatos de ambos bandos aceleró el golpe","El asesinato de Calvo Sotelo el 13 de julio fue el detonante inmediato del alzamiento militar","La internacionalización del conflicto con la intervención de Alemania Italia y la URSS prolongó la guerra"]'),
('historia-espana', 'bachillerato', '{2}', '["Las consecuencias de la Guerra Civil incluyeron cientos de miles de muertos y el exilio de medio millón","La represión franquista persiguió a los vencidos con ejecuciones cárcel y depuración profesional","La economía española quedó devastada y la autarquía de posguerra agravó la miseria","España quedó aislada internacionalmente tras la derrota de las potencias fascistas en 1945","La guerra dejó una herida profunda en la sociedad española que tardó décadas en cicatrizar"]'),
('historia-espana', 'bachillerato', '{2}', '["La dictadura franquista se apoyó en el ejército la Iglesia y el Movimiento Nacional como pilares","El régimen evolucionó desde la autarquía de los cuarenta al desarrollismo de los sesenta","El Plan de Estabilización de 1959 abrió la economía española al exterior y al turismo","El crecimiento económico de los sesenta transformó la sociedad española pero sin libertades políticas","La crisis del petróleo de 1973 y el envejecimiento de Franco aceleraron el agotamiento del régimen"]'),
('historia-espana', 'bachillerato', '{2}', '["Tras la muerte de Franco en noviembre de 1975 Juan Carlos I fue proclamado rey de España","El rey nombró a Adolfo Suárez presidente del gobierno para dirigir la reforma política","La Ley para la Reforma Política de 1976 desmontó el franquismo desde la legalidad vigente","La legalización del Partido Comunista en abril de 1977 fue un paso decisivo hacia la democracia","Las elecciones generales de junio de 1977 fueron las primeras democráticas en cuarenta y un años"]'),
('historia-espana', 'bachillerato', '{2}', '["La Constitución de 1978 fue fruto del consenso entre todas las fuerzas políticas parlamentarias","Establece España como un Estado social y democrático de derecho con monarquía parlamentaria","Reconoce las autonomías como forma de organización territorial del Estado","Garantiza los derechos fundamentales las libertades públicas y la abolición de la pena de muerte","Fue aprobada en referéndum el 6 de diciembre de 1978 con el apoyo del noventa por ciento de los votantes"]'),
('historia-espana', 'bachillerato', '{2}', '["El intento de golpe de Estado del 23 de febrero de 1981 fue protagonizado por el teniente coronel Tejero","Tejero asaltó el Congreso de los Diputados durante la votación de investidura de Calvo Sotelo","El rey Juan Carlos I se dirigió a la nación por televisión defendiendo la Constitución y la democracia","Las unidades militares sublevadas se rindieron y el golpe fracasó en pocas horas","El 23-F fortaleció la democracia española y demostró el compromiso de la sociedad con las libertades"]'),
('historia-espana', 'bachillerato', '{2}', '["El PSOE de Felipe González ganó las elecciones de 1982 con mayoría absoluta inaugurando una nueva etapa","España ingresó en la OTAN en 1982 y en la Comunidad Económica Europea en 1986","Los gobiernos socialistas modernizaron las infraestructuras la sanidad y la educación pública","España celebró los Juegos Olímpicos de Barcelona y la Expo de Sevilla en 1992","La alternancia democrática se consolidó con la llegada del PP de Aznar al poder en 1996"]'),
('historia-espana', 'bachillerato', '{2}', '["El Estado de las Autonomías creó diecisiete comunidades autónomas con competencias propias","Cataluña y el País Vasco accedieron a la autonomía por la vía rápida del artículo 151","El proceso autonómico se generalizó a todas las regiones durante los años ochenta","Las transferencias de competencias en educación sanidad y policía descentralizaron el Estado","El modelo autonómico ha generado debates sobre la financiación y el encaje de los nacionalismos"]'),
('historia-espana', 'bachillerato', '{2}', '["Al-Ándalus fue una sociedad culturalmente rica donde convivieron musulmanes cristianos y judíos","La cultura andalusí destacó en filosofía con Averroes y en medicina con Maimónides","La Alhambra de Granada y la Mezquita de Córdoba son joyas del arte islámico en España","La Reconquista avanzó durante siglos desde los núcleos cristianos del norte hacia el sur","La convivencia de las tres culturas dejó una huella profunda en la lengua el arte y las costumbres españolas"]'),
('historia-espana', 'bachillerato', '{2}', '["Los Borbones llegaron al trono español con Felipe V tras la Guerra de Sucesión en 1713","Los Decretos de Nueva Planta abolieron los fueros de la Corona de Aragón centralizando el Estado","Carlos III impulsó reformas ilustradas en educación economía y urbanismo durante el siglo XVIII","La España del XVIII experimentó un crecimiento demográfico y económico moderado","Las reformas borbónicas modernizaron la administración pero no resolvieron los problemas estructurales"]'),
('historia-espana', 'bachillerato', '{2}', '["La desamortización de Mendizábal en 1836 vendió los bienes de la Iglesia para financiar la guerra carlista","La desamortización de Madoz en 1855 afectó también a los bienes comunales de los ayuntamientos","Las desamortizaciones concentraron la tierra en manos de la burguesía sin beneficiar al campesinado","La industrialización española fue tardía y desigual concentrada en Cataluña y el País Vasco","El atraso agrario y la desigualdad social marcaron la España del siglo XIX y alimentaron el conflicto social"]'),
('historia-espana', 'bachillerato', '{2}', '["El descubrimiento de América en 1492 abrió una era de exploración y conquista del Nuevo Mundo","Hernán Cortés conquistó el Imperio Azteca entre 1519 y 1521 con alianzas indígenas y superioridad tecnológica","Pizarro conquistó el Imperio Inca entre 1532 y 1533 aprovechando las divisiones internas","El sistema colonial español organizó los territorios en virreinatos con una administración centralizada","La explotación minera y el comercio colonial enriquecieron a la Corona pero devastaron a las poblaciones indígenas"]'),
('historia-espana', 'bachillerato', '{2}', '["El reinado de Felipe II consolidó la hegemonía española con la unión de Portugal y las victorias en Lepanto","La Armada Invencible fue derrotada por Inglaterra en 1588 marcando el inicio del declive naval","La rebelión de los Países Bajos consumió enormes recursos militares durante décadas","La defensa del catolicismo en Europa enfrentó a España con Francia Inglaterra y los protestantes","Felipe II gobernó un imperio donde no se ponía el sol desde su despacho en El Escorial"]'),
('historia-espana', 'bachillerato', '{2}', '["La España del siglo XVII sufrió una profunda crisis demográfica económica y política","La expulsión de los moriscos en 1609 privó a la agricultura de mano de obra cualificada","El Conde-Duque de Olivares intentó centralizar la monarquía provocando la rebelión de Cataluña y Portugal","Portugal recuperó su independencia en 1640 tras sesenta años de unión con España","La Paz de Westfalia en 1648 y la de los Pirineos en 1659 confirmaron el declive de la hegemonía española"]'),
('historia-espana', 'bachillerato', '{2}', '["La Guerra de Sucesión Española enfrentó a los partidarios de Felipe de Anjou y Carlos de Austria","El conflicto fue también una guerra europea que involucró a Francia Austria Inglaterra y Holanda","La batalla de Almansa en 1707 aseguró el trono para Felipe V en el territorio peninsular","El Tratado de Utrecht de 1713 reconoció a Felipe V pero España perdió Gibraltar Menorca y los Países Bajos","La guerra consolidó la dinastía borbónica pero redujo significativamente el territorio y la influencia española"]'),
('historia-espana', 'bachillerato', '{2}', '["La Prehistoria peninsular incluye los yacimientos de Atapuerca con restos humanos de más de un millón de años","Las pinturas de Altamira representan el arte rupestre paleolítico de la cornisa cantábrica","Los pueblos prerromanos iberos y celtas habitaron la Península antes de la llegada de Roma","La conquista romana de Hispania comenzó en el 218 a.C. durante la segunda guerra púnica","La romanización transformó la Península con ciudades calzadas derecho y la lengua latina"]');
INSERT INTO ordena_historias (subject_id, level, grades, sentences) VALUES
('arte', 'bachillerato', '{2}', '["El Partenón de Atenas fue construido en el siglo V a.C. como templo dedicado a la diosa Atenea","Fidias dirigió la decoración escultórica con el friso de las Panateneas y las metopas","El orden dórico del Partenón alcanza la perfección con correcciones ópticas como la curvatura del estilóbato","La escultura griega evolucionó desde el hieratismo arcaico al naturalismo idealizado del periodo clásico","El arte griego estableció los cánones de belleza proporción y armonía que perviven en Occidente"]'),
('arte', 'bachillerato', '{2}', '["El arte románico se desarrolló en Europa entre los siglos XI y XIII vinculado a la Iglesia y el monacato","Las iglesias románicas tienen planta de cruz latina muros gruesos arcos de medio punto y poca luz","La escultura románica se subordina a la arquitectura decorando portadas y capiteles con función didáctica","La pintura mural románica usa colores planos y figuras hieráticas con finalidad catequética","El Camino de Santiago fue una vía de difusión del románico con iglesias de peregrinación como Santiago de Compostela"]'),
('arte', 'bachillerato', '{2}', '["El arte gótico surgió en Francia en el siglo XII con la abadía de Saint-Denis como primer ejemplo","La bóveda de crucería y el arco apuntado permitieron elevar las naves y abrir grandes ventanales","Las vidrieras de colores transformaron la luz interior de las catedrales en experiencia mística","La catedral de Chartres es un ejemplo paradigmático del gótico clásico francés del siglo XIII","La escultura gótica ganó naturalismo y expresividad liberándose progresivamente de la arquitectura"]'),
('arte', 'bachillerato', '{2}', '["El Quattrocento italiano renovó el arte con la perspectiva lineal la anatomía y el estudio de la antigüedad","Brunelleschi construyó la cúpula de Santa María del Fiore en Florencia como proeza técnica y estética","Masaccio introdujo la perspectiva y el volumen en la pintura con los frescos de la capilla Brancacci","Donatello recuperó la escultura exenta con el David en bronce primer desnudo desde la Antigüedad","Botticelli pintó El nacimiento de Venus y La primavera como alegorías del neoplatonismo florentino"]'),
('arte', 'bachillerato', '{2}', '["El Cinquecento romano alcanzó la plenitud del Renacimiento con Leonardo Miguel Ángel y Rafael","Leonardo experimentó con la composición piramidal y el sfumato en La Última Cena y la Gioconda","Miguel Ángel esculpió la Piedad del Vaticano y el David de Florencia como obras cumbre de la escultura","La bóveda de la Capilla Sixtina pintada por Miguel Ángel representa la Creación y el Juicio Final","Rafael sintetizó la armonía renacentista en La escuela de Atenas como celebración de la filosofía"]'),
('arte', 'bachillerato', '{2}', '["El Barroco surgió en Roma a finales del XVI como arte de la Contrarreforma católica","Bernini dominó la escultura y la arquitectura barroca con el Éxtasis de Santa Teresa y la columnata de San Pedro","Borromini revolucionó la arquitectura con plantas curvilíneas y fachadas ondulantes en San Carlo","Caravaggio introdujo el tenebrismo con contrastes violentos de luz y sombra en escenas religiosas","El Barroco buscó conmover al espectador con dramatismo movimiento y teatralidad"]'),
('arte', 'bachillerato', '{2}', '["Velázquez fue pintor de cámara de Felipe IV y el mayor artista del Barroco español","Las Meninas de 1656 revolucionaron la pintura con su complejo juego de miradas y espacios","La rendición de Breda muestra la generosidad del vencedor con una composición magistral de lanzas","Velázquez evolucionó hacia una pincelada suelta y vibrante que anticipa el impresionismo","Su dominio de la perspectiva aérea y la captación de la luz lo convierten en un pintor universal"]'),
('arte', 'bachillerato', '{2}', '["Goya comenzó como pintor de cartones para tapices con escenas populares alegres y luminosas","Como pintor de corte retrató a la familia real con un realismo que no ocultaba sus defectos","Los Desastres de la guerra grabaron los horrores de la invasión napoleónica con crudeza inédita","Los fusilamientos del 3 de mayo de 1808 denuncian la brutalidad de la represión francesa","Las Pinturas Negras de la Quinta del Sordo expresan una visión atormentada y moderna de la existencia"]'),
('arte', 'bachillerato', '{2}', '["El Impresionismo surgió en París en la década de 1870 como ruptura con la pintura académica","Monet pintó Impresión sol naciente en 1872 dando nombre involuntario al movimiento","Los impresionistas pintaban al aire libre capturando la luz y el color del instante con pinceladas sueltas","Renoir Degas y Pissarro exploraron distintas facetas de la vida moderna desde el ocio al trabajo","Las exposiciones independientes de los impresionistas desafiaron el sistema oficial de los Salones"]'),
('arte', 'bachillerato', '{2}', '["Cézanne buscó la estructura geométrica subyacente de la naturaleza anticipando el cubismo","Van Gogh expresó sus emociones a través del color puro y la pincelada expresiva y violenta","Gauguin abandonó la civilización europea buscando lo primitivo y lo exótico en Tahití","Toulouse-Lautrec retrató la vida nocturna parisina con influencia del grabado japonés","Los postimpresionistas sentaron las bases de todas las vanguardias artísticas del siglo XX"]'),
('arte', 'bachillerato', '{2}', '["El Cubismo nació en 1907 cuando Picasso pintó Las señoritas de Aviñón fragmentando las formas","Braque y Picasso desarrollaron el cubismo analítico descomponiendo los objetos en múltiples planos","El cubismo sintético simplificó las formas e introdujo el collage como técnica artística","El cubismo revolucionó la representación del espacio abandonando la perspectiva renacentista","La influencia del cubismo se extendió a la escultura la arquitectura y el diseño del siglo XX"]'),
('arte', 'bachillerato', '{2}', '["El Expresionismo surgió en Alemania a principios del XX como reacción al naturalismo y al impresionismo","El grupo Die Brücke fundado en Dresde en 1905 usó colores violentos y formas distorsionadas","El grupo Der Blaue Reiter de Múnich con Kandinsky buscó la expresión espiritual a través del arte","El grito de Munch de 1893 anticipó el expresionismo con su figura angustiada y paisaje ondulante","El expresionismo influyó en el cine el teatro y la literatura además de en las artes plásticas"]'),
('arte', 'bachillerato', '{2}', '["El Surrealismo se fundó oficialmente con el manifiesto de André Breton en 1924","Dalí desarrolló el método paranoico-crítico creando imágenes oníricas de una precisión perturbadora","Magritte cuestionó la relación entre imagen y realidad con obras como La traición de las imágenes","Miró creó un lenguaje de signos y colores puros que conectaba con lo primitivo y lo infantil","El surrealismo exploró el inconsciente los sueños y el azar como fuentes de creación artística"]'),
('arte', 'bachillerato', '{2}', '["Picasso pintó el Guernica en 1937 como denuncia del bombardeo de la villa vasca durante la Guerra Civil","El cuadro utiliza el blanco negro y gris para expresar el horror con una composición piramidal","Las figuras del toro el caballo la madre con el hijo muerto y la bombilla son símbolos del sufrimiento","El Guernica se exhibió en el pabellón español de la Exposición Internacional de París de 1937","La obra se convirtió en el símbolo universal del antibelicismo y los horrores de la guerra moderna"]'),
('arte', 'bachillerato', '{2}', '["La arquitectura del siglo XX pasó del historicismo al funcionalismo con la Bauhaus como referente","Le Corbusier formuló los cinco puntos de la nueva arquitectura: pilotis planta libre fachada libre ventana corrida y terraza jardín","Mies van der Rohe propuso el menos es más como principio de la arquitectura moderna","Frank Lloyd Wright integró la arquitectura con la naturaleza en la Casa de la Cascada","La arquitectura posmoderna reintrodujo la ornamentación y las referencias históricas desde los años setenta"]'),
('arte', 'bachillerato', '{2}', '["El arte abstracto surgió hacia 1910 con Kandinsky como uno de los primeros artistas no figurativos","Mondrian desarrolló el neoplasticismo con composiciones de líneas rectas y colores primarios","Malevich pintó el Cuadrado negro sobre fondo blanco en 1915 como icono del suprematismo","La abstracción liberó al arte de la representación de la realidad visible","El expresionismo abstracto americano de Pollock y Rothko dominó el arte de posguerra"]'),
('arte', 'bachillerato', '{2}', '["El Pop Art surgió en los años cincuenta en Gran Bretaña y se desarrolló en Estados Unidos","Andy Warhol convirtió la lata de sopa Campbell y a Marilyn Monroe en iconos del arte pop","Roy Lichtenstein adaptó el lenguaje del cómic al gran formato con puntos Ben-Day y colores planos","El Pop Art difuminó la frontera entre arte elevado y cultura popular de consumo","El movimiento reflejó y criticó la sociedad de consumo la publicidad y los medios de masas"]'),
('arte', 'bachillerato', '{2}', '["El arte islámico se desarrolló desde el siglo VII con una estética basada en la geometría y la caligrafía","La prohibición de representar figuras fomentó la decoración con arabescos atauriques y lacerías","La Alhambra de Granada es la obra cumbre del arte nazarí con sus patios fuentes y yeserías","La Mezquita de Córdoba destaca por su bosque de columnas con arcos bicolores de herradura","El arte mudéjar fusionó elementos islámicos y cristianos como estilo propio de la Península Ibérica"]'),
('arte', 'bachillerato', '{2}', '["Rubens dominó la pintura barroca flamenca con composiciones dinámicas y un colorido exuberante","Rembrandt revolucionó el retrato y el claroscuro con La ronda de noche y sus autorretratos","Vermeer pintó escenas íntimas de la vida doméstica holandesa con una luz serena y precisa","La pintura holandesa del XVII reflejó los valores de una sociedad burguesa protestante y comercial","El arte barroco del norte de Europa se distinguió del sur católico por sus temas civiles y cotidianos"]'),
('arte', 'bachillerato', '{2}', '["El arte paleocristiano nació en las catacumbas de Roma con pinturas simbólicas y sarcófagos esculpidos","El arte bizantino alcanzó su esplendor con Santa Sofía de Constantinopla y sus mosaicos dorados","Los mosaicos bizantinos de Rávena muestran la majestad imperial y la iconografía religiosa oriental","La querella iconoclasta del siglo VIII enfrentó a defensores y destructores de las imágenes sagradas","El arte bizantino pervivió durante un milenio influyendo en el románico y en el arte ortodoxo oriental"]'),
('arte', 'bachillerato', '{2}', '["El Rococó surgió en Francia a principios del XVIII como evolución ligera y decorativa del Barroco","Watteau pintó fiestas galantes con personajes aristocráticos en paisajes idílicos","Fragonard celebró el amor cortesano con escenas frívolas y una pincelada luminosa y ágil","El Rococó decoró palacios como Versalles con estucos dorados espejos y motivos vegetales","El Neoclasicismo reaccionó contra la frivolidad rococó recuperando la severidad del arte grecolatino"]'),
('arte', 'bachillerato', '{2}', '["David fue el pintor oficial de la Revolución Francesa y del Imperio napoleónico","El juramento de los Horacios de 1784 se convirtió en manifiesto del Neoclasicismo con su composición austera","Ingres llevó el clasicismo a la perfección del dibujo y la línea con retratos y desnudos idealizados","Canova esculpió Amor y Psique como obra maestra del Neoclasicismo en mármol","La arquitectura neoclásica imitó los templos griegos y romanos en edificios públicos y monumentos"]'),
('arte', 'bachillerato', '{2}', '["Delacroix lideró el Romanticismo pictórico francés con La libertad guiando al pueblo en 1830","Friedrich pintó paisajes sublimes con figuras solitarias contemplando la inmensidad de la naturaleza","Turner disolvió las formas en luz y color anticipando la abstracción con sus marinas y tormentas","Géricault denunció la tragedia de la balsa de la Medusa con un realismo dramático y monumental","El Romanticismo exaltó la emoción el individualismo y la naturaleza como alternativa al racionalismo"]'),
('arte', 'bachillerato', '{2}', '["Courbet proclamó el Realismo pictórico pintando trabajadores y escenas cotidianas sin idealización","El entierro en Ornans de 1850 escandalizó al público por tratar un funeral rural con formato monumental","Millet retrató la vida de los campesinos franceses en obras como El Ángelus y Las espigadoras","Daumier usó la caricatura y la pintura para denunciar la injusticia social y política","El Realismo preparó el camino para el Impresionismo al sacar la pintura del taller al mundo real"]'),
('arte', 'bachillerato', '{2}', '["El Modernismo o Art Nouveau renovó las artes decorativas y la arquitectura a finales del XIX","Gaudí desarrolló un estilo único en Barcelona con la Sagrada Familia el Parque Güell y la Casa Batlló","Klimt fundó la Secesión vienesa con pinturas decorativas y sensuales como El beso","Horta diseñó edificios con hierro y vidrio curvados siguiendo formas orgánicas en Bruselas","El Modernismo integró todas las artes buscando la belleza total en la vida cotidiana"]'),
('arte', 'bachillerato', '{2}', '["Rodin revolucionó la escultura moderna con obras como El pensador y Los burgueses de Calais","Brancusi simplificó las formas hasta la abstracción con esculturas como El beso y Pájaro en el espacio","Giacometti creó figuras humanas alargadas y frágiles que expresan la soledad existencial","Henry Moore exploró la forma orgánica con esculturas de figuras reclinadas y volúmenes perforados","La escultura del siglo XX se liberó del pedestal y del material tradicional para conquistar el espacio"]'),
('arte', 'bachillerato', '{2}', '["El futurismo italiano de Marinetti y Boccioni celebró la velocidad la máquina y la modernidad en 1909","El dadaísmo de Duchamp cuestionó qué es arte al presentar un urinario como obra en 1917","El constructivismo ruso de Tatlin y Rodchenko puso el arte al servicio de la revolución soviética","De Stijl holandés con Mondrian y Rietveld buscó un arte universal basado en la geometría pura","Las vanguardias históricas transformaron radicalmente la concepción del arte en las primeras décadas del XX"]'),
('arte', 'bachillerato', '{2}', '["El arte conceptual de los años sesenta priorizó la idea sobre la ejecución material de la obra","El Land Art intervino en el paisaje natural con obras efímeras como la Spiral Jetty de Smithson","El Minimalismo redujo la escultura a formas geométricas simples con artistas como Judd y Andre","El arte performativo o acción artística convirtió el cuerpo del artista en medio expresivo","El arte contemporáneo ha expandido sus límites incorporando instalaciones vídeo y tecnología digital"]'),
('arte', 'bachillerato', '{2}', '["La fotografía inventada en el siglo XIX transformó la relación del arte con la representación de la realidad","El cine surgió con los hermanos Lumière en 1895 y se convirtió en el arte del siglo XX por excelencia","El diseño gráfico e industrial se consolidó como disciplina artística con la Bauhaus en los años veinte","El arte digital y las nuevas tecnologías han creado formas de expresión impensables hace décadas","La democratización de la imagen ha transformado la creación artística y su relación con el público"]'),
('arte', 'bachillerato', '{2}', '["El Renacimiento español del XVI se manifestó en el plateresco como estilo decorativo en fachadas","El Escorial de Juan de Herrera encarna el estilo herreriano con su austeridad geométrica clasicista","El Greco fusionó la tradición bizantina y veneciana con un misticismo personal en Toledo","El entierro del conde de Orgaz combina lo terrenal y lo celestial con figuras alargadas y colores fríos","El arte español del XVI osciló entre la influencia italiana y una expresividad propia muy intensa"]'),
('arte', 'bachillerato', '{2}', '["La escultura barroca española destacó en la imaginería religiosa con pasos procesionales policromados","Gregorio Fernández creó cristos yacentes y vírgenes dolorosas con un realismo conmovedor en Valladolid","Alonso Cano y Pedro de Mena cultivaron una imaginería andaluza de belleza idealizada y devoción serena","Salzillo desarrolló la escultura procesional murciana del siglo XVIII con grupos escenográficos","La imaginería española es un arte único que fusiona escultura pintura y sentimiento religioso popular"]'),
('arte', 'bachillerato', '{2}', '["Zurbarán pintó santos y monjes con un tenebrismo silencioso y una austeridad contemplativa","Murillo retrató la religiosidad popular sevillana con vírgenes dulces y niños de la calle","Ribera trabajó en Nápoles combinando el tenebrismo caravaggesco con un realismo descarnado","La pintura barroca española del Siglo de Oro rivalizó con la italiana y la flamenca en calidad","El bodegón español alcanzó cotas de maestría con Sánchez Cotán y su composición geométrica de alimentos"]'),
('arte', 'bachillerato', '{2}', '["Dalí estudió en la Academia de Bellas Artes de Madrid y se unió al grupo surrealista en París","La persistencia de la memoria de 1931 con sus relojes blandos es su obra más icónica y reconocible","Miró desarrolló un lenguaje artístico propio con formas biomórficas estrellas y colores primarios","Tàpies fundó el informalismo español con pinturas matéricas que incorporan polvo arena y objetos","El arte español del siglo XX aportó figuras fundamentales a todos los movimientos de vanguardia"]'),
('arte', 'bachillerato', '{2}', '["El arte prerrománico asturiano del siglo IX anticipó soluciones arquitectónicas del románico","Santa María del Naranco fue construida como aula regia palatina con arcos de medio punto peraltados","El arte visigodo dejó iglesias como San Juan de Baños con el arco de herradura como elemento distintivo","San Pedro de la Nave destaca por sus capiteles esculpidos con escenas bíblicas del siglo VII","El prerrománico hispánico constituye un patrimonio artístico único anterior a las grandes corrientes europeas"]');
